     1→//! Event file reading and processing
     2→//!
     3→//! This module provides functionality for reading BIDS event files (.tsv format)
     4→//! and processing trial-by-trial experimental data.
     5→
     6→use std::collections::HashMap;
     7→use std::path::Path;
     8→use csv::ReaderBuilder;
     9→use serde::{Deserialize, Serialize};
    10→
    11→use crate::error::{BidsError, Result};
    12→use crate::file::BidsFile;
    13→use crate::io::utils;
    14→use super::BidsReader;
    15→
    16→/// Event data structure
    17→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    18→pub struct EventData {
    19→    /// Event onset times (in seconds)
    20→    pub onset: Vec<f64>,
    21→    /// Event durations (in seconds)
    22→    pub duration: Vec<f64>,
    23→    /// Trial types or event labels
    24→    pub trial_type: Vec<String>,
    25→    /// Additional event columns
    26→    pub additional_columns: HashMap<String, Vec<String>>,
    27→    /// File path where this data was loaded from
    28→    #[serde(skip)]
    29→    pub path: std::path::PathBuf,
    30→    /// Subject ID
    31→    pub subject: String,
    32→    /// Session ID (optional)
    33→    pub session: Option<String>,
    34→    /// Task name (optional)
    35→    pub task: Option<String>,
    36→    /// Run ID (optional)
    37→    pub run: Option<String>,
    38→    /// Structured event data
    39→    #[serde(skip)]
    40→    pub data: Vec<EventRecord>,
    41→}
    42→
    43→/// Individual event record
    44→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
    45→pub struct EventRecord {
    46→    /// Event onset time (in seconds)
    47→    pub onset: f64,
    48→    /// Event duration (in seconds)
    49→    pub duration: f64,
    50→    /// Trial type or event label
    51→    pub trial_type: String,
    52→    /// Additional event data
    53→    pub additional_data: HashMap<String, String>,
    54→}
    55→
    56→/// Event file reader
    57→pub struct EventsReader {
    58→    /// Column delimiter (default: tab)
    59→    delimiter: u8,
    60→    /// Whether to include additional columns
    61→    include_additional: bool,
    62→}
    63→
    64→impl EventsReader {
    65→    /// Create a new events reader
    66→    pub fn new() -> Self {
    67→        Self {
    68→            delimiter: b'\t',
    69→            include_additional: true,
    70→        }
    71→    }
    72→
    73→    /// Set the column delimiter
    74→    pub fn delimiter(mut self, delimiter: u8) -> Self {
    75→        self.delimiter = delimiter;
    76→        self
    77→    }
    78→
    79→    /// Set whether to include additional columns
    80→    pub fn include_additional(mut self, include: bool) -> Self {
    81→        self.include_additional = include;
    82→        self
    83→    }
    84→
    85→    /// Read events from a CSV reader
    86→    fn read_from_reader<R: std::io::Read>(&self, reader: R) -> Result<EventData> {
    87→        let mut csv_reader = ReaderBuilder::new()
    88→            .delimiter(self.delimiter)
    89→            .has_headers(true)
    90→            .from_reader(reader);
    91→
    92→        let headers = csv_reader.headers()?.clone();
    93→        
    94→        // Find required columns
    95→        let onset_col = headers.iter().position(|h| h == "onset")
    96→            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'onset' column"))?;
    97→        
    98→        let duration_col = headers.iter().position(|h| h == "duration")
    99→            .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing 'duration' column"))?;
   100→        
   101→        let trial_type_col = headers.iter().position(|h| h == "trial_type");
   102→        
   103→        // Initialize vectors
   104→        let mut onset = Vec::new();
   105→        let mut duration = Vec::new();
   106→        let mut trial_type = Vec::new();
   107→        let mut additional_columns: HashMap<String, Vec<String>> = HashMap::new();
   108→
   109→        // Initialize additional columns
   110→        if self.include_additional {
   111→            for (i, header) in headers.iter().enumerate() {
   112→                if i != onset_col && i != duration_col && Some(i) != trial_type_col {
   113→                    additional_columns.insert(header.to_string(), Vec::new());
   114→                }
   115→            }
   116→        }
   117→
   118→        // Read records
   119→        for result in csv_reader.records() {
   120→            let record = result?;
   121→            
   122→            // Parse onset
   123→            let onset_str = record.get(onset_col)
   124→                .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing onset value"))?;
   125→            let onset_val = onset_str.parse::<f64>()
   126→                .map_err(|_| BidsError::parse_error("events.tsv", "Invalid onset value"))?;
   127→            onset.push(onset_val);
   128→            
   129→            // Parse duration
   130→            let duration_str = record.get(duration_col)
   131→                .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing duration value"))?;
   132→            let duration_val = duration_str.parse::<f64>()
   133→                .map_err(|_| BidsError::parse_error("events.tsv", "Invalid duration value"))?;
   134→            duration.push(duration_val);
   135→            
   136→            // Parse trial_type
   137→            let trial_type_val = if let Some(col) = trial_type_col {
   138→                record.get(col)
   139→                    .ok_or_else(|| BidsError::parse_error("events.tsv", "Missing trial_type value"))?
   140→                    .to_string()
   141→            } else {
   142→                "n/a".to_string()
   143→            };
   144→            trial_type.push(trial_type_val);
   145→            
   146→            // Parse additional columns
   147→            if self.include_additional {
   148→                for (i, value) in record.iter().enumerate() {
   149→                    if i != onset_col && i != duration_col && Some(i) != trial_type_col {
   150→                        let header = &headers[i];
   151→                        if let Some(col_vec) = additional_columns.get_mut(header) {
   152→                            col_vec.push(value.to_string());
   153→                        }
   154→                    }
   155→                }
   156→            }
   157→        }
   158→
   159→        // Create event records
   160→        let mut data = Vec::with_capacity(onset.len());
   161→        for i in 0..onset.len() {
   162→            let mut additional_data = HashMap::new();
   163→            for (col, values) in &additional_columns {
   164→                if let Some(value) = values.get(i) {
   165→                    additional_data.insert(col.clone(), value.clone());
   166→                }
   167→            }
   168→            
   169→            data.push(EventRecord {
   170→                onset: onset[i],
   171→                duration: duration[i],
   172→                trial_type: trial_type[i].clone(),
   173→                additional_data,
   174→            });
   175→        }
   176→        
   177→        Ok(EventData {
   178→            onset,
   179→            duration,
   180→            trial_type,
   181→            additional_columns,
   182→            path: std::path::PathBuf::new(),
   183→            subject: String::new(),
   184→            session: None,
   185→            task: None,
   186→            run: None,
   187→            data,
   188→        })
   189→    }
   190→
   191→    /// Convert EventData to individual records
   192→    pub fn to_records(&self, data: &EventData) -> Vec<EventRecord> {
   193→        let mut records = Vec::new();
   194→        
   195→        for i in 0..data.onset.len() {
   196→            let mut additional_data = HashMap::new();
   197→            
   198→            // Collect additional data for this record
   199→            for (col_name, col_values) in &data.additional_columns {
   200→                if let Some(value) = col_values.get(i) {
   201→                    additional_data.insert(col_name.clone(), value.clone());
   202→                }
   203→            }
   204→            
   205→            records.push(EventRecord {
   206→                onset: data.onset[i],
   207→                duration: data.duration[i],
   208→                trial_type: data.trial_type[i].clone(),
   209→                additional_data,
   210→            });
   211→        }
   212→        
   213→        records
   214→    }
   215→}
   216→
   217→impl Default for EventsReader {
   218→    fn default() -> Self {
   219→        Self::new()
   220→    }
   221→}
   222→
   223→impl BidsReader<EventData> for EventsReader {
   224→    fn read(&self, file: &BidsFile) -> Result<EventData> {
   225→        if !file.is_events() {
   226→            return Err(BidsError::validation_error(
   227→                "File is not an events file",
   228→                Some("suffix".to_string()),
   229→            ));
   230→        }
   231→        
   232→        self.read_path(&file.path)
   233→    }
   234→
   235→    fn read_path(&self, path: &Path) -> Result<EventData> {
   236→        if !utils::is_readable(path) {
   237→            return Err(BidsError::file_not_found(path));
   238→        }
   239→        
   240→        let file = std::fs::File::open(path)?;
   241→        self.read_from_reader(file)
   242→    }
   243→}
   244→
   245→impl EventData {
   246→    /// Create a new empty EventData
   247→    pub fn new() -> Self {
   248→        Self {
   249→            onset: Vec::new(),
   250→            duration: Vec::new(),
   251→            trial_type: Vec::new(),
   252→            additional_columns: HashMap::new(),
   253→            path: std::path::PathBuf::new(),
   254→            subject: String::new(),
   255→            session: None,
   256→            task: None,
   257→            run: None,
   258→            data: Vec::new(),
   259→        }
   260→    }
   261→
   262→    /// Get the number of events
   263→    pub fn len(&self) -> usize {
   264→        self.onset.len()
   265→    }
   266→
   267→    /// Check if the event data is empty
   268→    pub fn is_empty(&self) -> bool {
   269→        self.onset.is_empty()
   270→    }
   271→
   272→    /// Get unique trial types
   273→    pub fn unique_trial_types(&self) -> Vec<String> {
   274→        let mut types: Vec<String> = self.trial_type.iter().cloned().collect();
   275→        types.sort();
   276→        types.dedup();
   277→        types
   278→    }
   279→
   280→    /// Filter events by trial type
   281→    pub fn filter_by_trial_type(&self, trial_type: &str) -> Self {
   282→        let mut filtered = EventData::new();
   283→        // Preserve metadata
   284→        filtered.path = self.path.clone();
   285→        filtered.subject = self.subject.clone();
   286→        filtered.session = self.session.clone();
   287→        filtered.task = self.task.clone();
   288→        filtered.run = self.run.clone();
   289→        
   290→        for (i, t_type) in self.trial_type.iter().enumerate() {
   291→            if t_type == trial_type {
   292→                filtered.onset.push(self.onset[i]);
   293→                filtered.duration.push(self.duration[i]);
   294→                filtered.trial_type.push(t_type.clone());
   295→                
   296→                // Copy additional columns
   297→                for (col_name, col_values) in &self.additional_columns {
   298→                    if let Some(value) = col_values.get(i) {
   299→                        filtered.additional_columns
   300→                            .entry(col_name.clone())
   301→                            .or_insert_with(Vec::new)
   302→                            .push(value.clone());
   303→                    }
   304→                }
   305→                
   306→                // Add to structured data
   307→                if let Some(record) = self.data.get(i) {
   308→                    filtered.data.push(record.clone());
   309→                }
   310→            }
   311→        }
   312→        
   313→        filtered
   314→    }
   315→
   316→    /// Get events within a time range
   317→    pub fn filter_by_time_range(&self, start: f64, end: f64) -> Self {
   318→        let mut filtered = EventData::new();
   319→        // Preserve metadata
   320→        filtered.path = self.path.clone();
   321→        filtered.subject = self.subject.clone();
   322→        filtered.session = self.session.clone();
   323→        filtered.task = self.task.clone();
   324→        filtered.run = self.run.clone();
   325→        
   326→        for (i, &onset) in self.onset.iter().enumerate() {
   327→            if onset >= start && onset <= end {
   328→                filtered.onset.push(onset);
   329→                filtered.duration.push(self.duration[i]);
   330→                filtered.trial_type.push(self.trial_type[i].clone());
   331→                
   332→                // Copy additional columns
   333→                for (col_name, col_values) in &self.additional_columns {
   334→                    if let Some(value) = col_values.get(i) {
   335→                        filtered.additional_columns
   336→                            .entry(col_name.clone())
   337→                            .or_insert_with(Vec::new)
   338→                            .push(value.clone());
   339→                    }
   340→                }
   341→                
   342→                // Add to structured data
   343→                if let Some(record) = self.data.get(i) {
   344→                    filtered.data.push(record.clone());
   345→                }
   346→            }
   347→        }
   348→        
   349→        filtered
   350→    }
   351→
   352→    /// Get summary statistics
   353→    pub fn summary(&self) -> EventSummary {
   354→        let n_events = self.len();
   355→        let unique_types = self.unique_trial_types();
   356→        
   357→        let total_duration = self.duration.iter().sum();
   358→        let min_duration = self.duration.iter().fold(f64::INFINITY, |a, &b| a.min(b));
   359→        let max_duration = self.duration.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
   360→        let mean_duration = if n_events > 0 { total_duration / n_events as f64 } else { 0.0 };
   361→        
   362→        let min_onset = self.onset.iter().fold(f64::INFINITY, |a, &b| a.min(b));
   363→        let max_onset = self.onset.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
   364→        
   365→        EventSummary {
   366→            n_events,
   367→            n_trial_types: unique_types.len(),
   368→            trial_types: unique_types,
   369→            total_duration,
   370→            mean_duration,
   371→            min_duration,
   372→            max_duration,
   373→            min_onset,
   374→            max_onset,
   375→        }
   376→    }
   377→}
   378→
   379→impl Default for EventData {
   380→    fn default() -> Self {
   381→        Self::new()
   382→    }
   383→}
   384→
   385→/// Summary statistics for event data
   386→#[derive(Debug, Clone, Serialize, Deserialize)]
   387→pub struct EventSummary {
   388→    /// Number of events
   389→    pub n_events: usize,
   390→    /// Number of unique trial types
   391→    pub n_trial_types: usize,
   392→    /// List of trial types
   393→    pub trial_types: Vec<String>,
   394→    /// Total duration of all events
   395→    pub total_duration: f64,
   396→    /// Mean event duration
   397→    pub mean_duration: f64,
   398→    /// Minimum event duration
   399→    pub min_duration: f64,
   400→    /// Maximum event duration
   401→    pub max_duration: f64,
   402→    /// Minimum onset time
   403→    pub min_onset: f64,
   404→    /// Maximum onset time
   405→    pub max_onset: f64,
   406→}
   407→
   408→impl std::fmt::Display for EventSummary {
   409→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
   410→        writeln!(f, "Event Summary")?;
   411→        writeln!(f, "Events: {}", self.n_events)?;
   412→        writeln!(f, "Trial Types: {}", self.n_trial_types)?;
   413→        writeln!(f, "Types: {}", self.trial_types.join(", "))?;
   414→        writeln!(f, "Duration: {:.3} - {:.3} (mean: {:.3})", 
   415→                 self.min_duration, self.max_duration, self.mean_duration)?;
   416→        writeln!(f, "Onset Range: {:.3} - {:.3}", self.min_onset, self.max_onset)?;
   417→        Ok(())
   418→    }
   419→}
   420→
   421→/// Convenience function to read events from a path
   422→pub fn read_events<P: AsRef<Path>>(path: P) -> Result<EventData> {
   423→    let reader = EventsReader::new();
   424→    reader.read_path(path.as_ref())
   425→}
   426→
   427→#[cfg(test)]
   428→mod tests {
   429→    use super::*;
   430→    use tempfile::TempDir;
   431→    use std::fs;
   432→
   433→    fn create_test_events_file() -> Result<(TempDir, std::path::PathBuf)> {
   434→        let temp_dir = TempDir::new()?;
   435→        let file_path = temp_dir.path().join("sub-01_task-test_events.tsv");
   436→        
   437→        let content = "onset\tduration\ttrial_type\tresponse\n\
   438→                       0.0\t2.0\tgolden\t1\n\
   439→                       5.0\t2.0\tgolden\t1\n\
   440→                       10.0\t2.0\tscrambled\t0\n\
   441→                       15.0\t2.0\tscrambled\t0\n";
   442→        
   443→        fs::write(&file_path, content)?;
   444→        Ok((temp_dir, file_path))
   445→    }
   446→
   447→    #[test]
   448→    fn test_read_events_file() -> Result<()> {
   449→        let (_temp_dir, file_path) = create_test_events_file()?;
   450→        
   451→        let events = read_events(&file_path)?;
   452→        
   453→        assert_eq!(events.len(), 4);
   454→        assert_eq!(events.onset, vec![0.0, 5.0, 10.0, 15.0]);
   455→        assert_eq!(events.duration, vec![2.0, 2.0, 2.0, 2.0]);
   456→        assert_eq!(events.trial_type, vec!["golden", "golden", "scrambled", "scrambled"]);
   457→        assert!(events.additional_columns.contains_key("response"));
   458→        
   459→        Ok(())
   460→    }
   461→
   462→    #[test]
   463→    fn test_events_reader_configuration() -> Result<()> {
   464→        let (_temp_dir, file_path) = create_test_events_file()?;
   465→        
   466→        let reader = EventsReader::new()
   467→            .delimiter(b'\t')
   468→            .include_additional(false);
   469→        
   470→        let events = reader.read_path(&file_path)?;
   471→        
   472→        assert_eq!(events.len(), 4);
   473→        assert!(events.additional_columns.is_empty());
   474→        
   475→        Ok(())
   476→    }
   477→
   478→    #[test]
   479→    fn test_event_data_filtering() -> Result<()> {
   480→        let (_temp_dir, file_path) = create_test_events_file()?;
   481→        let events = read_events(&file_path)?;
   482→        
   483→        // Filter by trial type
   484→        let golden_events = events.filter_by_trial_type("golden");
   485→        assert_eq!(golden_events.len(), 2);
   486→        assert_eq!(golden_events.trial_type, vec!["golden", "golden"]);
   487→        
   488→        // Filter by time range
   489→        let early_events = events.filter_by_time_range(0.0, 10.0);
   490→        assert_eq!(early_events.len(), 3);
   491→        
   492→        Ok(())
   493→    }
   494→
   495→    #[test]
   496→    fn test_event_summary() -> Result<()> {
   497→        let (_temp_dir, file_path) = create_test_events_file()?;
   498→        let events = read_events(&file_path)?;
   499→        
   500→        let summary = events.summary();
   501→        
   502→        assert_eq!(summary.n_events, 4);
   503→        assert_eq!(summary.n_trial_types, 2);
   504→        assert_eq!(summary.trial_types, vec!["golden", "scrambled"]);
   505→        assert_eq!(summary.total_duration, 8.0);
   506→        assert_eq!(summary.mean_duration, 2.0);
   507→        assert_eq!(summary.min_onset, 0.0);
   508→        assert_eq!(summary.max_onset, 15.0);
   509→        
   510→        Ok(())
   511→    }
   512→
   513→    #[test]
   514→    fn test_to_records() -> Result<()> {
   515→        let (_temp_dir, file_path) = create_test_events_file()?;
   516→        let events = read_events(&file_path)?;
   517→        
   518→        let reader = EventsReader::new();
   519→        let records = reader.to_records(&events);
   520→        
   521→        assert_eq!(records.len(), 4);
   522→        assert_eq!(records[0].onset, 0.0);
   523→        assert_eq!(records[0].trial_type, "golden");
   524→        assert_eq!(records[0].additional_data.get("response"), Some(&"1".to_string()));
   525→        
   526→        Ok(())
   527→    }
   528→
   529→    #[test]
   530→    fn test_unique_trial_types() -> Result<()> {
   531→        let (_temp_dir, file_path) = create_test_events_file()?;
   532→        let events = read_events(&file_path)?;
   533→        
   534→        let unique_types = events.unique_trial_types();
   535→        assert_eq!(unique_types, vec!["golden", "scrambled"]);
   536→        
   537→        Ok(())
   538→    }
   539→
   540→    #[test]
   541→    fn test_invalid_events_file() {
   542→        let temp_dir = TempDir::new().unwrap();
   543→        let file_path = temp_dir.path().join("invalid_events.tsv");
   544→        
   545→        // Missing required columns
   546→        let content = "trial_type\tresponse\n\
   547→                       golden\t1\n\
   548→                       scrambled\t0\n";
   549→        
   550→        fs::write(&file_path, content).unwrap();
   551→        
   552→        let result = read_events(&file_path);
   553→        assert!(result.is_err());
   554→    }
   555→}

