   245→
   246→        if nan_indices.is_empty() {
   247→            return Ok(());
   248→        }
   249→
   250→        match self.missing_strategy {
   251→            MissingStrategy::Zero => {
   252→                for &idx in &nan_indices {
   253→                    data[idx] = 0.0;
   254→                }
   255→            }
   256→            MissingStrategy::Mean => {
   257→                let valid_values: Vec<f64> = data.iter()
   258→                    .filter(|&&x| !x.is_nan())
   259→                    .copied()
   260→                    .collect();
   261→                
   262→                if valid_values.is_empty() {
   263→                    return Err(BidsError::parse_error(
   264→                        "confounds.tsv",
   265→                        &format!("Variable '{}' has no valid values", var_name),
   266→                    ));
   267→                }
   268→
   269→                let mean = valid_values.iter().sum::<f64>() / valid_values.len() as f64;
   270→                for &idx in &nan_indices {
   271→                    data[idx] = mean;
   272→                }
   273→            }
   274→            MissingStrategy::Median => {
   275→                let mut valid_values: Vec<f64> = data.iter()
   276→                    .filter(|&&x| !x.is_nan())
   277→                    .copied()
   278→                    .collect();
   279→                
   280→                if valid_values.is_empty() {
   281→                    return Err(BidsError::parse_error(
   282→                        "confounds.tsv",
   283→                        &format!("Variable '{}' has no valid values", var_name),
   284→                    ));
   285→                }
   286→
   287→                valid_values.sort_by(|a, b| a.partial_cmp(b).unwrap());
   288→                let median = if valid_values.len() % 2 == 0 {
   289→                    (valid_values[valid_values.len() / 2 - 1] + valid_values[valid_values.len() / 2]) / 2.0
   290→                } else {
   291→                    valid_values[valid_values.len() / 2]
   292→                };
   293→
   294→                for &idx in &nan_indices {
   295→                    data[idx] = median;
   296→                }
   297→            }
   298→            MissingStrategy::Remove => {
   299→                // This is more complex and would require removing entire rows
   300→                // For now, just replace with zero
   301→                for &idx in &nan_indices {
   302→                    data[idx] = 0.0;
   303→                }
   304→            }
   305→            MissingStrategy::Keep => {
   306→                // Do nothing - keep NaN values
   307→            }
   308→        }
   309→
   310→        Ok(())
   311→    }
   312→}
