   469→    /// Select specific columns by name
   470→    pub fn select_columns(&self, columns: &[String]) -> Result<Self> {
   471→        let mut selected_variables = HashMap::new();
   472→        let mut selected_names = Vec::new();
   473→        
   474→        for col in columns {
   475→            if let Some(data) = self.variables.get(col) {
   476→                selected_variables.insert(col.clone(), data.clone());
   477→                selected_names.push(col.clone());
   478→            } else {
   479→                // Check canonical mappings
   480→                let canonical = match col.to_lowercase().as_str() {
   481→                    "csf" => "CSF",
   482→                    "white_matter" | "wm" => "WhiteMatter",
   483→                    "global_signal" | "gsr" => "GlobalSignal",
   484→                    _ => col.as_str(),
   485→                };
   486→                
   487→                if let Some(data) = self.variables.get(canonical) {
   488→                    selected_variables.insert(canonical.to_string(), data.clone());
   489→                    selected_names.push(canonical.to_string());
   490→                }
   491→            }
   492→        }
   493→        
   494→        Ok(Self {
   495→            variables: selected_variables,
   496→            string_variables: HashMap::new(),
