   508→    /// Convert confound data to matrix format for PCA
   509→    pub fn to_matrix(&self) -> Result<DMatrix<f64>> {
   510→        if self.variables.is_empty() {
   511→            return Err(BidsError::analysis_error("No variables to convert to matrix", None));
   512→        }
   513→        
   514→        let n_rows = self.n_timepoints;
   515→        let n_cols = self.variables.len();
   516→        let mut data = Vec::with_capacity(n_rows * n_cols);
   517→        
   518→        // Data is stored column-major in nalgebra
   519→        for var_name in &self.variable_names {
   520→            if let Some(var_data) = self.variables.get(var_name) {
   521→                data.extend(var_data);
   522→            }
   523→        }
   524→        
   525→        Ok(DMatrix::from_vec(n_rows, n_cols, data))
   526→    }
