   528→    /// Get summary statistics
   529→    pub fn summary(&self) -> ConfoundsSummary {
   530→        let mut variable_stats = HashMap::new();
   531→
   532→        for (var_name, data) in &self.variables {
   533→            let valid_data: Vec<f64> = data.iter().filter(|&&x| !x.is_nan()).copied().collect();
   534→            
   535→            if !valid_data.is_empty() {
   536→                let mean = valid_data.iter().sum::<f64>() / valid_data.len() as f64;
   537→                let variance = valid_data.iter().map(|x| (x - mean).powi(2)).sum::<f64>() / (valid_data.len() - 1) as f64;
   538→                let std_dev = variance.sqrt();
   539→                let min = valid_data.iter().fold(f64::INFINITY, |a, &b| a.min(b));
   540→                let max = valid_data.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
   541→
   542→                variable_stats.insert(var_name.clone(), VariableStats {
   543→                    mean,
   544→                    std_dev,
   545→                    min,
   546→                    max,
   547→                    n_valid: valid_data.len(),
   548→                    n_missing: data.len() - valid_data.len(),
   549→                });
   550→            }
   551→        }
   552→
   553→        ConfoundsSummary {
   554→            n_variables: self.n_variables(),
   555→            n_timepoints: self.n_timepoints,
   556→            variable_names: self.variable_names.clone(),
   557→            variable_stats,
   558→        }
   559→    }
