   561→    /// Check if a column exists
   562→    pub fn has_column(&self, column_name: &str) -> bool {
   563→        // First check direct column name
   564→        if self.variables.contains_key(column_name) {
   565→            return true;
   566→        }
   567→        
   568→        // Then check canonical mappings
   569→        let canonical = match column_name {
   570→            "motion" => {
   571→                // Check if any motion parameter exists
   572→                return self.variables.keys().any(|k| {
   573→                    k.starts_with("trans_") || k.starts_with("rot_")
   574→                });
   575→            }
   576→            "csf" => "csf",
   577→            "wm" | "white_matter" => "white_matter",
   578→            "gm" | "gray_matter" | "grey_matter" => "gray_matter",
   579→            "global_signal" => "global_signal",
   580→            _ => column_name,
   581→        };
   582→        
   583→        self.variables.contains_key(canonical)
   584→    }
