   586→    /// Select specific columns
   587→    pub fn select_columns(&self, columns: &[String]) -> Result<Self> {
   588→        let mut selected_vars = HashMap::new();
   589→        let mut selected_names = Vec::new();
   590→        
   591→        for col in columns {
   592→            // Handle canonical names
   593→            match col.as_str() {
   594→                "motion" => {
   595→                    // Add all motion parameters
   596→                    for (name, data) in &self.variables {
   597→                        if name.starts_with("trans_") || name.starts_with("rot_") {
   598→                            selected_vars.insert(name.clone(), data.clone());
   599→                            if !selected_names.contains(name) {
   600→                                selected_names.push(name.clone());
   601→                            }
   602→                        }
   603→                    }
   604→                }
   605→                "csf" => {
   606→                    if let Some(data) = self.variables.get("csf") {
   607→                        selected_vars.insert("csf".to_string(), data.clone());
   608→                        selected_names.push("csf".to_string());
   609→                    } else if let Some(data) = self.variables.get("CSF") {
   610→                        selected_vars.insert("CSF".to_string(), data.clone());
   611→                        selected_names.push("CSF".to_string());
   612→                    }
   613→                }
   614→                "wm" | "white_matter" => {
   615→                    if let Some(data) = self.variables.get("white_matter") {
   616→                        selected_vars.insert("white_matter".to_string(), data.clone());
   617→                        selected_names.push("white_matter".to_string());
   618→                    } else if let Some(data) = self.variables.get("WhiteMatter") {
   619→                        selected_vars.insert("WhiteMatter".to_string(), data.clone());
   620→                        selected_names.push("WhiteMatter".to_string());
   621→                    }
   622→                }
   623→                _ => {
   624→                    // Direct column name
   625→                    if let Some(data) = self.variables.get(col) {
   626→                        selected_vars.insert(col.clone(), data.clone());
   627→                        selected_names.push(col.clone());
   628→                    }
   629→                }
   630→            }
   631→        }
   632→        
   633→        if selected_vars.is_empty() {
   634→            return Err(BidsError::validation_error(
   635→                "No matching columns found",
   636→                Some(columns.join(", ")),
   637→            ));
   638→        }
   639→        
   640→        Ok(Self {
   641→            variables: selected_vars,
   642→            string_variables: HashMap::new(),
   643→            variable_names: selected_names,
   644→            n_timepoints: self.n_timepoints,
   645→            path: self.path.clone(),
   646→            subject: self.subject.clone(),
   647→            session: self.session.clone(),
   648→            task: self.task.clone(),
   649→            run: self.run.clone(),
   650→            pca_result: None,
   651→        })
   652→    }
   653→    
   654→    /// Convert to matrix for PCA
   655→    pub fn to_matrix(&self) -> Result<nalgebra::DMatrix<f64>> {
   656→        if self.variables.is_empty() {
   657→            return Err(BidsError::validation_error(
   658→                "No numeric variables available for matrix conversion",
   659→                None,
   660→            ));
   661→        }
   662→        
   663→        let n_rows = self.n_timepoints;
   664→        let n_cols = self.variables.len();
   665→        let mut data = Vec::with_capacity(n_rows * n_cols);
   666→        
   667→        // Fill data column by column (column-major order for nalgebra)
   668→        for var_name in &self.variable_names {
   669→            if let Some(var_data) = self.variables.get(var_name) {
   670→                data.extend_from_slice(var_data);
   671→            }
   672→        }
   673→        
   674→        Ok(nalgebra::DMatrix::from_vec(n_rows, n_cols, data))
   675→    }
   676→}
