    }

    fn create_test_confounds_file() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("sub-01_task-test_desc-confounds_regressors.tsv");

        let content = "trans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\tcsf\twhite_matter\n\
                       0.1\t0.2\t0.3\t0.01\t0.02\t0.03\t100.0\t200.0\n\
                       0.2\t0.3\t0.4\t0.02\t0.03\t0.04\t101.0\t201.0\n\
                       0.3\t0.4\t0.5\t0.03\t0.04\t0.05\t102.0\t202.0\n\
                       0.4\t0.5\t0.6\t0.04\t0.05\t0.06\t103.0\t203.0\n";

        fs::write(&file_path, content)?;
        Ok((temp_dir, file_path))
    }

