    if !columns.iter().any(|col| col == "onset") {
        return Err(BidsError::validation_error(
            "Missing required 'onset' column in events file",
            Some("onset".to_string()),
        ));
    }

    if !columns.iter().any(|col| col == "duration") {
        return Err(BidsError::validation_error(
            "Missing required 'duration' column in events file",
            Some("duration".to_string()),
        ));
    }

    // Validate data types
    if let Ok(onset_col) = df.column("onset") {
        if !onset_col.dtype().is_primitive_numeric() {
            return Err(BidsError::validation_error(
                "Column 'onset' must be numeric",
                Some("onset".to_string()),
            ));
        }
    }

    if let Ok(duration_col) = df.column("duration") {
        if !duration_col.dtype().is_primitive_numeric() {
            return Err(BidsError::validation_error(
                "Column 'duration' must be numeric",
                Some("duration".to_string()),
            ));
        }
    }

    Ok(())
}

/// Validate that confounds DataFrame has expected structure
fn validate_confounds_columns(df: &DataFrame) -> Result<()> {
    let columns = df.get_column_names();

    if columns.is_empty() {
        return Err(BidsError::validation_error(
            "Confounds file has no columns",
            None,
        ));
    }

    // Check that at least some columns are numeric (confounds should be mostly numeric)
    let numeric_count = columns
        .iter()
        .filter_map(|name| df.column(name).ok())
        .filter(|col| col.dtype().is_primitive_numeric())
        .count();

    if numeric_count == 0 {
        return Err(BidsError::validation_error(
            "Confounds file has no numeric columns",
            None,
        ));
    }

    Ok(())
}

