        assert_eq!(df.height(), 4);
        assert_eq!(df.width(), 4);

        // Check column names
        let columns = df.get_column_names();
        assert!(columns.iter().any(|col| col == "onset"));
        assert!(columns.iter().any(|col| col == "duration"));
        assert!(columns.iter().any(|col| col == "trial_type"));
        assert!(columns.iter().any(|col| col == "response"));

        // Check data types
        assert!(df.column("onset")?.dtype().is_numeric());
        assert!(df.column("duration")?.dtype().is_numeric());

        Ok(())
    }

