    fn test_events_validation() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("invalid_events.tsv");

        // Missing required columns
        let content = "trial_type\tresponse\n\
                       golden\t1\n\
                       scrambled\t0\n";

        fs::write(&file_path, content)?;

        let result = read_events_df(&file_path);
        assert!(result.is_err());

        Ok(())
    }

    #[test]
    fn test_confounds_validation() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("invalid_confounds.tsv");

        // No numeric columns
        let content = "subject\tsession\n\
                       01\t1\n\
                       01\t2\n";

        fs::write(&file_path, content)?;

        let result = read_confounds_df(&file_path);
        assert!(result.is_err());

        Ok(())
    }

    #[test]
    fn test_lazy_operations() -> Result<()> {
        let (_temp_dir, file_path) = create_test_events_file()?;

        let lazy_df = read_tsv_lazy(&file_path)?;

        // Filter and select using lazy operations
        let result = lazy_df
            .filter(col("trial_type").eq(lit("golden")))
            .select([col("onset"), col("duration")])
            .collect()?;

        assert_eq!(result.height(), 2); // Should have 2 golden trials
        assert_eq!(result.width(), 2);  // onset and duration columns

        Ok(())
    }
}

