}

/// Create a lazy frame for efficient operations on large datasets
///
/// This function reads a BIDS TSV file into a lazy Polars DataFrame, which allows
/// for efficient chaining of operations without immediate execution.
///
/// # Arguments
///
/// * `path` - Path to the TSV file
///
/// # Returns
///
/// Returns a `Result<LazyFrame>` that can be used for lazy operations
///
/// # Example
///
/// ```rust,no_run
/// use bids_rust::dataframes::read_tsv_lazy;
