        assert_eq!(df.height(), 4);
        assert_eq!(df.width(), 4);

        // Check column names
        let columns = df.get_column_names();
        assert!(columns.iter().any(|col| col.as_str() == "onset"));
        assert!(columns.iter().any(|col| col.as_str() == "duration"));
        assert!(columns.iter().any(|col| col.as_str() == "trial_type"));
        assert!(columns.iter().any(|col| col.as_str() == "response"));

        // Check data types
        assert!(df.column("onset")?.dtype().is_primitive_numeric());
        assert!(df.column("duration")?.dtype().is_primitive_numeric());

        Ok(())
    }

    #[test]
    fn test_read_confounds_df() -> Result<()> {
        let (_temp_dir, file_path) = create_test_confounds_file()?;

