//! Builder patterns for I/O operations

use std::collections::HashMap;
use crate::{BidsProject, EventData, ConfoundsData, Result, BidsError};
use crate::io::{EventsReader, ConfoundsReader, BidsReader};
use crate::search::SearchBuilder;
use crate::analysis::pca::PcaProcessor;

/// Builder for reading event files with filtering options
pub struct EventsBuilder<'a> {
    project: &'a BidsProject,
    filters: HashMap<String, String>,
    flat: bool,
}

impl<'a> EventsBuilder<'a> {
    /// Create a new events builder
    pub fn new(project: &'a BidsProject) -> Self {
        Self {
            project,
            filters: HashMap::new(),
            flat: false,
        }
    }

    /// Filter by subject
    pub fn subject(mut self, subject: impl Into<String>) -> Self {
        self.filters.insert("sub".to_string(), subject.into());
        self
    }

    /// Filter by session
    pub fn session(mut self, session: impl Into<String>) -> Self {
        self.filters.insert("ses".to_string(), session.into());
        self
    }

    /// Filter by task
    pub fn task(mut self, task: impl Into<String>) -> Self {
        self.filters.insert("task".to_string(), task.into());
        self
    }

    /// Filter by run
    pub fn run(mut self, run: impl Into<String>) -> Self {
        self.filters.insert("run".to_string(), run.into());
        self
    }

    /// Whether to return flat output
    pub fn flat(mut self, flat: bool) -> Self {
        self.flat = flat;
        self
    }

    /// Collect all matching event files
    pub fn collect(self) -> Result<Vec<EventData>> {
        // Find event files using search builder
        let mut search = self.project.search_files()
            .suffix("events")
            .extension("tsv");

        // Apply filters
        for (key, value) in self.filters {
            match key.as_str() {
                "sub" => search = search.subject(value),
                "ses" => search = search.session(value),
                "task" => search = search.task(value),
                "run" => search = search.run(value),
                _ => {}
            }
        }

        let files = search.collect()?;
        let reader = EventsReader::new();

        let mut results = Vec::new();
        for file in files {
            match reader.read(&file) {
                Ok(mut event_data) => {
                    // Extract metadata from file
                    event_data.subject = file.entities.get("sub").cloned().unwrap_or_default();
                    event_data.session = file.entities.get("ses").cloned();
                    event_data.task = file.entities.get("task").cloned();
                    event_data.run = file.entities.get("run").cloned();
                    event_data.path = file.path.clone();

                    results.push(event_data);
                }
                Err(e) => {
                    eprintln!("Warning: Failed to read event file {:?}: {}", file.path, e);
                }
            }
        }

        Ok(results)
    }
}

/// Builder for reading confound files with filtering and processing options
pub struct ConfoundsBuilder<'a> {
    project: &'a BidsProject,
    filters: HashMap<String, String>,
    columns: Option<Vec<String>>,
    pca_components: Option<usize>,
    flat: bool,
}

impl<'a> ConfoundsBuilder<'a> {
    /// Create a new confounds builder
    pub fn new(project: &'a BidsProject) -> Self {
        Self {
            project,
            filters: HashMap::new(),
            columns: None,
            pca_components: None,
            flat: false,
        }
    }

    /// Filter by subject
    pub fn subject(mut self, subject: impl Into<String>) -> Self {
        self.filters.insert("sub".to_string(), subject.into());
        self
    }

    /// Filter by session
    pub fn session(mut self, session: impl Into<String>) -> Self {
        self.filters.insert("ses".to_string(), session.into());
        self
    }

    /// Filter by task
    pub fn task(mut self, task: impl Into<String>) -> Self {
        self.filters.insert("task".to_string(), task.into());
        self
    }

    /// Filter by run
    pub fn run(mut self, run: impl Into<String>) -> Self {
        self.filters.insert("run".to_string(), run.into());
        self
    }

    /// Select specific columns
    pub fn columns(mut self, columns: &[&str]) -> Self {
        self.columns = Some(columns.iter().map(|&s| s.to_string()).collect());
        self
    }

    /// Apply PCA with specified number of components
    pub fn with_pca(mut self, n_components: usize) -> Self {
        self.pca_components = Some(n_components);
        self
    }

    /// Whether to return flat output
    pub fn flat(mut self, flat: bool) -> Self {
        self.flat = flat;
        self
    }

    /// Collect all matching confound files
    pub fn collect(self) -> Result<Vec<ConfoundsData>> {
        // Find confound files using search builder
        let mut search = self.project.search_files()
            .in_derivatives(true)
            .suffix("timeseries")
            .extension("tsv");

        // Apply filters
        for (key, value) in self.filters {
            match key.as_str() {
                "sub" => search = search.subject(value),
                "ses" => search = search.session(value),
                "task" => search = search.task(value),
                "run" => search = search.run(value),
                _ => {}
            }
        }

        // Also search for files with desc-confounds
        let mut search2 = self.project.search_files()
            .in_derivatives(true)
            .desc("confounds")
            .extension("tsv");

        for (key, value) in &self.filters {
            match key.as_str() {
                "sub" => search2 = search2.subject(value.clone()),
                "ses" => search2 = search2.session(value.clone()),
                "task" => search2 = search2.task(value.clone()),
                "run" => search2 = search2.run(value.clone()),
                _ => {}
            }
        }

        let mut files = search.collect()?;
        let files2 = search2.collect()?;

        // Merge and deduplicate
        for file in files2 {
            if !files.iter().any(|f| f.path == file.path) {
                files.push(file);
            }
        }

        let reader = ConfoundsReader::new();

        let mut results = Vec::new();
        for file in files {
            match reader.read(&file) {
                Ok(mut confound_data) => {
                    // Extract metadata from file
                    confound_data.subject = file.entities.get("sub").cloned().unwrap_or_default();
                    confound_data.session = file.entities.get("ses").cloned();
                    confound_data.task = file.entities.get("task").cloned();
                    confound_data.run = file.entities.get("run").cloned();
                    confound_data.path = file.path.clone();

                    // Apply column selection
                    if let Some(ref cols) = self.columns {
                        confound_data = confound_data.select_columns(cols)?;
                    }

                    // Apply PCA if requested
                    if let Some(n_components) = self.pca_components {
                        let processor = PcaProcessor::new();
                        let data_matrix = confound_data.to_matrix()?;
                        let pca_result = processor.fit_transform(&data_matrix, Some(n_components))?;
                        confound_data.pca_result = Some(pca_result);
                    }

                    results.push(confound_data);
                }
                Err(e) => {
                    eprintln!("Warning: Failed to read confound file {:?}: {}", file.path, e);
                }
            }
        }

        Ok(results)
    }
}

impl BidsProject {
    /// Create a builder for reading event files
    pub fn read_events(&self) -> EventsBuilder {
        EventsBuilder::new(self)
    }

    /// Create a builder for reading confound files
    pub fn read_confounds(&self) -> ConfoundsBuilder {
        ConfoundsBuilder::new(self)
    }

    /// Get repetition time from a functional file's sidecar
    pub fn get_repetition_time(&self, file_path: &std::path::Path) -> Result<Option<f64>> {
        // Convert path to string and replace extension with .json
        let path_str = file_path.to_string_lossy();
        let json_path = if path_str.ends_with(".nii.gz") {
            path_str.replace(".nii.gz", ".json")
        } else if path_str.ends_with(".nii") {
            path_str.replace(".nii", ".json")
        } else {
            return Ok(None);
        };

        // Check if sidecar exists
        let json_path = std::path::Path::new(&json_path);
        if !json_path.exists() {
            return Ok(None);
        }

        // Read and parse JSON
        let content = std::fs::read_to_string(json_path)?;
        let json: serde_json::Value = serde_json::from_str(&content)?;

        // Extract RepetitionTime
        if let Some(tr) = json.get("RepetitionTime") {
            if let Some(tr_value) = tr.as_f64() {
                return Ok(Some(tr_value));
            }
        }

        Ok(None)
    }
}

