//! BIDS compliance checking
//!
//! This module provides tools for validating BIDS datasets against
//! the BIDS specification.

use std::path::{Path, PathBuf};
use std::collections::HashMap;
use serde_json::Value;
use walkdir::WalkDir;

use crate::error::{BidsError, Result};
use crate::project::BidsProject;
use crate::file::BidsFile;

/// Severity level for compliance issues
#[derive(Debug, Clone, PartialEq, Eq, Hash, PartialOrd, Ord)]
pub enum Severity {
    /// Critical issues that prevent the dataset from being BIDS-compliant
    Critical,
    /// High priority issues that should be addressed
    High,
    /// Medium priority issues
    Medium,
    /// Low priority issues or recommendations
    Low,
}

/// A compliance issue found during validation
#[derive(Debug, Clone)]
pub struct ComplianceIssue {
    /// Severity of the issue
    pub severity: Severity,
    /// Description of the issue
    pub description: String,
    /// File path associated with the issue (if applicable)
    pub file: Option<PathBuf>,
    /// Rule that was violated
    pub rule: String,
}

/// Result of a compliance check
#[derive(Debug, Clone)]
pub struct ComplianceResult {
    /// Whether the dataset passed all critical checks
    pub passed: bool,
    /// List of issues found
    pub issues: Vec<ComplianceIssue>,
    /// Number of files checked
    pub files_checked: usize,
}

/// BIDS compliance checker
pub struct ComplianceChecker {
    /// Whether to check for optional recommendations
    check_recommendations: bool,
    /// Whether to check derivatives
    check_derivatives: bool,
}

impl ComplianceChecker {
    /// Create a new compliance checker
    pub fn new() -> Self {
        Self {
            check_recommendations: true,
            check_derivatives: true,
        }
    }

    /// Set whether to check for optional recommendations
    pub fn check_recommendations(mut self, check: bool) -> Self {
        self.check_recommendations = check;
        self
    }

    /// Set whether to check derivatives
    pub fn check_derivatives(mut self, check: bool) -> Self {
        self.check_derivatives = check;
        self
    }

    /// Check compliance of a BIDS project
    pub fn check_project(&self, project: &BidsProject) -> Result<ComplianceResult> {
        let mut issues = Vec::new();
        let mut files_checked = 0;

        // Check required files
        self.check_required_files(project, &mut issues)?;

        // Check participants.tsv
        self.check_participants_file(project, &mut issues)?;

        // Check dataset_description.json
        self.check_dataset_description(project, &mut issues)?;

        // Check subject directories
        self.check_subject_directories(project, &mut issues, &mut files_checked)?;

        // Check if there are any critical issues
        let passed = !issues.iter().any(|issue| issue.severity == Severity::Critical);

        Ok(ComplianceResult {
            passed,
            issues,
            files_checked,
        })
    }

    /// Check for required files
    fn check_required_files(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
        // Check participants.tsv
        let participants_file = project.path.join("participants.tsv");
        if !participants_file.exists() {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "Missing required participants.tsv file".to_string(),
                file: Some(participants_file),
                rule: "participants.tsv".to_string(),
            });
        }

        // Check dataset_description.json
        let dataset_description = project.path.join("dataset_description.json");
        if !dataset_description.exists() {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "Missing required dataset_description.json file".to_string(),
                file: Some(dataset_description),
                rule: "dataset_description.json".to_string(),
            });
        }

        Ok(())
    }

    /// Check participants.tsv file
    fn check_participants_file(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
        let participants_file = project.path.join("participants.tsv");
        if !participants_file.exists() {
            return Ok(()); // Already checked in check_required_files
        }

        // Read and validate participants.tsv
        let content = std::fs::read_to_string(&participants_file)?;
        let lines: Vec<&str> = content.lines().collect();

        if lines.is_empty() {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "participants.tsv is empty".to_string(),
                file: Some(participants_file.clone()),
                rule: "participants_empty".to_string(),
            });
            return Ok(());
        }

        // Check header
        let header = lines[0];
        let columns: Vec<&str> = header.split('\t').collect();

        if columns.is_empty() || columns[0] != "participant_id" {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "participants.tsv must have 'participant_id' as first column".to_string(),
                file: Some(participants_file.clone()),
                rule: "participants_header".to_string(),
            });
        }

        // Validate participant IDs
        for (i, line) in lines.iter().skip(1).enumerate() {
            if line.is_empty() { continue; }

            let fields: Vec<&str> = line.split('\t').collect();
            if fields.is_empty() { continue; }

            let participant_id = fields[0];
            if !participant_id.starts_with("sub-") {
                issues.push(ComplianceIssue {
                    severity: Severity::Critical,
                    description: format!("Invalid participant ID '{}' on line {}: must start with 'sub-'", 
                                       participant_id, i + 2),
                    file: Some(participants_file.clone()),
                    rule: "participant_id_format".to_string(),
                });
            }

            // Check if participant directory exists
            let participant_dir = project.path.join(participant_id);
            if !participant_dir.exists() {
                issues.push(ComplianceIssue {
                    severity: Severity::High,
                    description: format!("Participant '{}' listed in participants.tsv but directory not found", 
                                       participant_id),
                    file: Some(participants_file.clone()),
                    rule: "participant_directory_missing".to_string(),
                });
            }
        }

        Ok(())
    }

    /// Check dataset_description.json file
    fn check_dataset_description(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
        // Check required fields in dataset description
        if let Some(name) = project.description.get("Name") {
            if name.as_str().map_or(true, |s| s.is_empty()) {
                issues.push(ComplianceIssue {
                    severity: Severity::Critical,
                    description: "Dataset name is missing or empty".to_string(),
                    file: Some(project.path.join("dataset_description.json")),
                    rule: "dataset_description.Name".to_string(),
                });
            }
        } else {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "Dataset name is missing from dataset_description.json".to_string(),
                file: Some(project.path.join("dataset_description.json")),
                rule: "dataset_description.Name".to_string(),
            });
        }

        // Check BIDS version
        if let Some(bids_version) = project.description.get("BIDSVersion") {
            if bids_version.as_str().map_or(true, |s| s.is_empty()) {
                issues.push(ComplianceIssue {
                    severity: Severity::High,
                    description: "BIDSVersion is missing or empty".to_string(),
                    file: Some(project.path.join("dataset_description.json")),
                    rule: "dataset_description.BIDSVersion".to_string(),
                });
            }
        } else {
            issues.push(ComplianceIssue {
                severity: Severity::High,
                description: "BIDSVersion is missing from dataset_description.json".to_string(),
                file: Some(project.path.join("dataset_description.json")),
                rule: "dataset_description.BIDSVersion".to_string(),
            });
        }

        Ok(())
    }

    /// Check subject directories
    fn check_subject_directories(&self, project: &BidsProject, issues: &mut Vec<ComplianceIssue>, files_checked: &mut usize) -> Result<()> {
        for participant in &project.participants {
            let subject_dir = project.path.join(format!("sub-{}", participant.id));

            if !subject_dir.exists() {
                issues.push(ComplianceIssue {
                    severity: Severity::Critical,
                    description: format!("Subject directory sub-{} does not exist", participant.id),
                    file: Some(subject_dir),
                    rule: "subject_directory".to_string(),
                });
                continue;
            }

            // Check subject directory structure
            self.check_subject_directory(&subject_dir.as_path(), &participant.id, issues, files_checked)?;
        }

        Ok(())
    }

    /// Check a single subject directory
    fn check_subject_directory(&self, subject_dir: &Path, subject_id: &str, issues: &mut Vec<ComplianceIssue>, files_checked: &mut usize) -> Result<()> {
        // Check directory naming convention
        if !subject_dir.file_name().unwrap().to_str().unwrap().starts_with("sub-") {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "Subject directory must start with 'sub-'".to_string(),
                file: Some(subject_dir.to_path_buf()),
                rule: "subject_directory_naming".to_string(),
            });
        }

        // Walk through subject directory
        for entry in WalkDir::new(subject_dir).min_depth(1).max_depth(3) {
            let entry = entry?;
            let path = entry.path();

            if path.is_file() {
                *files_checked += 1;

                // Check file naming
                if let Some(file_name) = path.file_name().and_then(|f| f.to_str()) {
                    self.check_file_naming(path, file_name, subject_id, issues)?;

                    // Check JSON sidecars have corresponding data files
                    if file_name.ends_with(".json") && !file_name.contains("dataset_description") {
                        self.check_json_sidecar(path, issues)?;
                    }
                }
            } else if path.is_dir() {
                // Check session/modality directory naming
                if let Some(dir_name) = path.file_name().and_then(|f| f.to_str()) {
                    self.check_directory_naming(path, dir_name, issues)?;
                }
            }
        }

        Ok(())
    }

    /// Check file naming conventions
    fn check_file_naming(&self, path: &Path, file_name: &str, subject_id: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
        // Skip hidden files and common metadata files
        if file_name.starts_with('.') || file_name == "participants.tsv" || file_name == "dataset_description.json" {
            return Ok(());
        }

        // Check if file follows BIDS naming convention
        let valid_extensions = vec![".nii", ".nii.gz", ".json", ".tsv", ".tsv.gz", ".bval", ".bvec"];
        let has_valid_extension = valid_extensions.iter().any(|ext| file_name.ends_with(ext));

        if !has_valid_extension {
            issues.push(ComplianceIssue {
                severity: Severity::Medium,
                description: format!("File has non-standard extension: {}", file_name),
                file: Some(path.to_path_buf()),
                rule: "file_extension".to_string(),
            });
        }

        // Check for valid BIDS entities
        if file_name.contains('_') {
            let parts: Vec<&str> = file_name.split('_').collect();
            for part in &parts[..parts.len()-1] { // Skip the suffix
                if part.contains('-') && !self.is_valid_entity(part) {
                    issues.push(ComplianceIssue {
                        severity: Severity::High,
                        description: format!("Invalid BIDS entity: {}", part),
                        file: Some(path.to_path_buf()),
                        rule: "bids_entity".to_string(),
                    });
                }
            }
        }

        Ok(())
    }

    /// Check if an entity is valid
    fn is_valid_entity(&self, entity: &str) -> bool {
        let valid_entities = vec![
            "sub", "ses", "task", "acq", "ce", "rec", "dir", "run", "mod",
            "echo", "flip", "inv", "mt", "part", "proc", "hemi", "space",
            "split", "recording", "chunk", "seg", "label", "desc"
        ];

        if let Some(key) = entity.split('-').next() {
            valid_entities.contains(&key)
        } else {
            false
        }
    }

    /// Check directory naming conventions
    fn check_directory_naming(&self, path: &Path, dir_name: &str, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
        // Check session directories
        if dir_name.contains("ses") && !dir_name.starts_with("ses-") {
            issues.push(ComplianceIssue {
                severity: Severity::Critical,
                description: "Session directory must start with 'ses-'".to_string(),
                file: Some(path.to_path_buf()),
                rule: "session_directory_naming".to_string(),
            });
        }

        // Check modality directories
        let valid_modalities = vec!["anat", "func", "dwi", "fmap", "perf", "meg", "eeg", "ieeg", "beh"];
        if !valid_modalities.contains(&dir_name) && !dir_name.starts_with("ses-") && !dir_name.starts_with("sub-") {
            if self.check_recommendations {
                issues.push(ComplianceIssue {
                    severity: Severity::Low,
                    description: format!("Non-standard modality directory: {}", dir_name),
                    file: Some(path.to_path_buf()),
                    rule: "modality_directory".to_string(),
                });
            }
        }

        Ok(())
    }

    /// Check JSON sidecar files have corresponding data files
    fn check_json_sidecar(&self, json_path: &Path, issues: &mut Vec<ComplianceIssue>) -> Result<()> {
        let json_name = json_path.file_stem().unwrap().to_str().unwrap();
        let parent = json_path.parent().unwrap();

        // Check for corresponding .nii/.nii.gz file
        let nii_path = parent.join(format!("{}.nii", json_name));
        let nii_gz_path = parent.join(format!("{}.nii.gz", json_name));

        if !nii_path.exists() && !nii_gz_path.exists() {
            // Check if it's a task events JSON
            if !json_name.contains("events") {
                issues.push(ComplianceIssue {
                    severity: Severity::Medium,
                    description: format!("JSON sidecar {} has no corresponding data file", json_path.display()),
                    file: Some(json_path.to_path_buf()),
                    rule: "orphaned_sidecar".to_string(),
                });
            }
        }

        Ok(())
    }
}

impl Default for ComplianceChecker {
    fn default() -> Self {
        Self::new()
    }
}

/// Quick compliance check for a BIDS project
pub fn check_compliance(project: &BidsProject) -> Result<ComplianceResult> {
    let checker = ComplianceChecker::new();
    checker.check_project(project)
}

impl ComplianceResult {
    /// Get a summary of issues by severity
    pub fn summary(&self) -> HashMap<Severity, usize> {
        let mut summary = HashMap::new();
        for issue in &self.issues {
            *summary.entry(issue.severity.clone()).or_insert(0) += 1;
        }
        summary
    }

    /// Get all critical issues
    pub fn critical_issues(&self) -> Vec<&ComplianceIssue> {
        self.issues.iter()
            .filter(|issue| issue.severity == Severity::Critical)
            .collect()
    }

    /// Check if there are any issues of a given severity
    pub fn has_issues_of_severity(&self, severity: &Severity) -> bool {
        self.issues.iter().any(|issue| &issue.severity == severity)
    }
}

impl std::fmt::Display for ComplianceResult {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "BIDS Compliance Check Result")?;
        writeln!(f, "Status: {}", if self.passed { "PASSED" } else { "FAILED" })?;
        writeln!(f, "Files checked: {}", self.files_checked)?;
        writeln!(f, "Total issues: {}", self.issues.len())?;

        if !self.issues.is_empty() {
            writeln!(f, "\nIssues by severity:")?;
            let summary = self.summary();
            for (severity, count) in summary {
                writeln!(f, "  {:?}: {}", severity, count)?;
            }

            writeln!(f, "\nDetailed issues:")?;
            for (i, issue) in self.issues.iter().enumerate() {
                writeln!(f, "{}. [{:?}] {}", i + 1, issue.severity, issue.description)?;
                if let Some(file) = &issue.file {
                    writeln!(f, "   File: {}", file.display())?;
                }
                writeln!(f, "   Rule: {}", issue.rule)?;
            }
        }

        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::project::BidsProject;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_project() -> Result<(TempDir, BidsProject)> {
        let temp_dir = TempDir::new()?;
        let root = temp_dir.path();

        // Create minimal BIDS structure
        let participants_content = "participant_id\nsub-01\nsub-02\n";
        fs::write(root.join("participants.tsv"), participants_content)?;

        let dataset_description = serde_json::json!({
            "Name": "Test Dataset",
            "BIDSVersion": "1.8.0"
        });
        fs::write(
            root.join("dataset_description.json"),
            serde_json::to_string_pretty(&dataset_description)?,
        )?;

        // Create subject directories
        fs::create_dir_all(root.join("sub-01"))?;
        fs::create_dir_all(root.join("sub-02"))?;

        let project = BidsProject::new(root)?;
        Ok((temp_dir, project))
    }

    #[test]
    fn test_compliance_checker_creation() {
        let checker = ComplianceChecker::new();
        assert!(checker.check_recommendations);
        assert!(checker.check_derivatives);
    }

    #[test]
    fn test_compliance_check_valid_project() -> Result<()> {
        let (_temp_dir, project) = create_test_project()?;
        let result = check_compliance(&project)?;

        assert!(result.passed);
        assert!(result.issues.is_empty());

        Ok(())
    }

    #[test]
    fn test_compliance_check_missing_files() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let root = temp_dir.path();

        // Create dataset_description.json but not participants.tsv
        let dataset_description = serde_json::json!({
            "Name": "Test Dataset",
            "BIDSVersion": "1.8.0"
        });
        fs::write(
            root.join("dataset_description.json"),
            serde_json::to_string_pretty(&dataset_description)?,
        )?;

        // This should fail during project creation
        let result = BidsProject::new(root);
        assert!(result.is_err());

        Ok(())
    }

    #[test]
    fn test_compliance_checker_configuration() {
        let checker = ComplianceChecker::new()
            .check_recommendations(false)
            .check_derivatives(false);

        assert!(!checker.check_recommendations);
        assert!(!checker.check_derivatives);
    }

    #[test]
    fn test_compliance_issue_creation() {
        let issue = ComplianceIssue {
            severity: Severity::Critical,
            description: "Test issue".to_string(),
            file: Some(PathBuf::from("/test/path")),
            rule: "test_rule".to_string(),
        };

        assert_eq!(issue.severity, Severity::Critical);
        assert_eq!(issue.description, "Test issue");
        assert_eq!(issue.rule, "test_rule");
    }
}

