//! Principal Component Analysis (PCA) implementation
//!
//! This module provides PCA functionality for confound variable processing,
//! matching the behavior of R's prcomp function.

use nalgebra::{DMatrix, SVD};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

use crate::error::{BidsError, Result};

/// PCA processor for confound variables
#[derive(Debug, Clone)]
pub struct PcaProcessor {
    /// Data matrix (observations x variables)
    pub data: DMatrix<f64>,
    /// Variable names
    pub variable_names: Vec<String>,
    /// Whether to center the data
    pub center: bool,
    /// Whether to scale the data
    pub scale: bool,
}

/// Result of PCA computation
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct PcaResult {
    /// Principal component scores (observations x components)
    pub scores: Vec<Vec<f64>>,
    /// Principal component loadings (variables x components)
    pub loadings: Vec<Vec<f64>>,
    /// Explained variance for each component
    pub explained_variance: Vec<f64>,
    /// Explained variance ratio for each component
    pub explained_variance_ratio: Vec<f64>,
    /// Cumulative explained variance ratio
    pub cumulative_variance_ratio: Vec<f64>,
    /// Standard deviations of principal components
    pub standard_deviations: Vec<f64>,
    /// Means of original variables (if centered)
    pub means: Vec<f64>,
    /// Standard deviations of original variables (if scaled)
    pub scales: Vec<f64>,
    /// Variable names
    pub variable_names: Vec<String>,
}

impl PcaProcessor {
    /// Create a new PCA processor
    pub fn new(data: DMatrix<f64>, variable_names: Vec<String>) -> Result<Self> {
        if data.ncols() != variable_names.len() {
            return Err(BidsError::analysis_error(
                "Number of variables must match number of variable names",
                None,
            ));
        }

        Ok(Self {
            data,
            variable_names,
            center: true,
            scale: true,
        })
    }

    /// Create PCA processor from a vector of variable data
    pub fn from_variables(variables: Vec<(String, Vec<f64>)>) -> Result<Self> {
        if variables.is_empty() {
            return Err(BidsError::analysis_error("No variables provided", None));
        }

        let n_obs = variables[0].1.len();
        let n_vars = variables.len();

        // Check that all variables have the same number of observations
        for (name, data) in &variables {
            if data.len() != n_obs {
                return Err(BidsError::analysis_error(
                    format!("Variable '{}' has {} observations, expected {}", name, data.len(), n_obs),
                    None,
                ));
            }
        }

        // Create data matrix
        let mut data_matrix = DMatrix::zeros(n_obs, n_vars);
        let mut variable_names = Vec::with_capacity(n_vars);

        for (j, (name, data)) in variables.into_iter().enumerate() {
            variable_names.push(name);
            for (i, value) in data.into_iter().enumerate() {
                data_matrix[(i, j)] = value;
            }
        }

        Self::new(data_matrix, variable_names)
    }

    /// Create PCA processor from a HashMap of confound variables
    pub fn from_confound_map(confounds: HashMap<String, Vec<f64>>) -> Result<Self> {
        let variables: Vec<(String, Vec<f64>)> = confounds.into_iter().collect();
        Self::from_variables(variables)
    }

    /// Set whether to center the data
    pub fn center(mut self, center: bool) -> Self {
        self.center = center;
        self
    }

    /// Set whether to scale the data
    pub fn scale(mut self, scale: bool) -> Self {
        self.scale = scale;
        self
    }

    /// Compute PCA
    pub fn compute(&self) -> Result<PcaResult> {
        let mut data = self.data.clone();
        let mut means = vec![0.0; self.data.ncols()];
        let mut scales = vec![1.0; self.data.ncols()];

        // Center the data
        if self.center {
            for j in 0..data.ncols() {
                let col = data.column(j);
                let mean = col.mean();
                means[j] = mean;

                for i in 0..data.nrows() {
                    data[(i, j)] -= mean;
                }
            }
        }

        // Scale the data
        if self.scale {
            for j in 0..data.ncols() {
                let col = data.column(j);
                let variance = col.map(|x| x.powi(2)).sum() / (data.nrows() - 1) as f64;
                let std_dev = variance.sqrt();

                if std_dev < f64::EPSILON {
                    return Err(BidsError::math_error(
                        format!("Variable '{}' has zero variance", self.variable_names[j]),
                        None,
                    ));
                }

                scales[j] = std_dev;

                for i in 0..data.nrows() {
                    data[(i, j)] /= std_dev;
                }
            }
        }

        // Perform SVD
        let svd = SVD::new(data.clone(), true, true);

        let u = svd.u.ok_or_else(|| {
            BidsError::math_error("SVD failed to compute U matrix", None)
        })?;

        let v_t = svd.v_t.ok_or_else(|| {
            BidsError::math_error("SVD failed to compute V^T matrix", None)
        })?;

        let singular_values = svd.singular_values;
        let n_components = singular_values.len();

        // Calculate explained variance
        let total_variance = singular_values.iter().map(|s| s.powi(2)).sum::<f64>();
        let explained_variance: Vec<f64> = singular_values
            .iter()
            .map(|s| s.powi(2) / (data.nrows() - 1) as f64)
            .collect();

        let explained_variance_ratio: Vec<f64> = explained_variance
            .iter()
            .map(|var| var / total_variance * (data.nrows() - 1) as f64)
            .collect();

        let cumulative_variance_ratio: Vec<f64> = explained_variance_ratio
            .iter()
            .scan(0.0, |acc, &x| {
                *acc += x;
                Some(*acc)
            })
            .collect();

        // Calculate standard deviations
        let standard_deviations: Vec<f64> = explained_variance
            .iter()
            .map(|var| var.sqrt())
            .collect();

        // Extract scores (principal components)
        let scores_matrix = &u * DMatrix::from_diagonal(&singular_values);
        let scores: Vec<Vec<f64>> = (0..scores_matrix.nrows())
            .map(|i| scores_matrix.row(i).iter().cloned().collect())
            .collect();

        // Extract loadings (eigenvectors)
        let loadings: Vec<Vec<f64>> = (0..v_t.ncols())
            .map(|j| v_t.column(j).iter().cloned().collect())
            .collect();

        Ok(PcaResult {
            scores,
            loadings,
            explained_variance,
            explained_variance_ratio,
            cumulative_variance_ratio,
            standard_deviations,
            means,
            scales,
            variable_names: self.variable_names.clone(),
        })
    }

    /// Compute PCA with specified number of components
    pub fn compute_n_components(&self, n_components: usize) -> Result<PcaResult> {
        let mut result = self.compute()?;

        if n_components < result.scores[0].len() {
            // Truncate to requested number of components
            for scores_row in &mut result.scores {
                scores_row.truncate(n_components);
            }

            for loadings_row in &mut result.loadings {
                loadings_row.truncate(n_components);
            }

            result.explained_variance.truncate(n_components);
            result.explained_variance_ratio.truncate(n_components);
            result.cumulative_variance_ratio.truncate(n_components);
            result.standard_deviations.truncate(n_components);
        }

        Ok(result)
    }

    /// Compute PCA retaining components that explain at least the specified variance
    pub fn compute_variance_threshold(&self, variance_threshold: f64) -> Result<PcaResult> {
        let result = self.compute()?;

        // Find number of components needed to explain the variance
        let n_components = result
            .cumulative_variance_ratio
            .iter()
            .position(|&ratio| ratio >= variance_threshold)
            .unwrap_or(result.cumulative_variance_ratio.len())
            + 1;

        self.compute_n_components(n_components.min(result.explained_variance.len()))
    }

    /// Compute PCA with memory optimization for large datasets
    /// Uses truncated computation for datasets with many variables
    #[allow(dead_code)]
    pub fn compute_optimized(&self) -> Result<PcaResult> {
        // For small datasets, use regular computation
        if self.data.ncols() <= 1000 && self.data.nrows() <= 10000 {
            return self.compute();
        }

        // For large datasets, compute only top components
        let n_components = if self.data.ncols() > 1000 {
            (self.data.ncols() / 10).max(50).min(200)
        } else {
            // If many observations but few variables, still limit components
            self.data.ncols().min(100)
        };

        self.compute_n_components(n_components)
    }

    /// Check if the dataset is large enough to benefit from optimization
    pub fn should_optimize(&self) -> bool {
        self.data.ncols() > 1000 || self.data.nrows() > 10000
    }
}

impl PcaResult {
    /// Get the number of components
    pub fn n_components(&self) -> usize {
        self.explained_variance.len()
    }

    /// Get the number of observations
    pub fn n_observations(&self) -> usize {
        self.scores.len()
    }

    /// Get the number of variables
    pub fn n_variables(&self) -> usize {
        self.variable_names.len()
    }

    /// Get scores as a matrix
    pub fn scores_matrix(&self) -> DMatrix<f64> {
        let n_obs = self.n_observations();
        let n_comp = self.n_components();

        let mut matrix = DMatrix::zeros(n_obs, n_comp);
        for (i, row) in self.scores.iter().enumerate() {
            for (j, &value) in row.iter().enumerate() {
                matrix[(i, j)] = value;
            }
        }
        matrix
    }

    /// Get loadings as a matrix
    pub fn loadings_matrix(&self) -> DMatrix<f64> {
        let n_vars = self.n_variables();
        let n_comp = self.n_components();

        let mut matrix = DMatrix::zeros(n_vars, n_comp);
        for (i, row) in self.loadings.iter().enumerate() {
            for (j, &value) in row.iter().enumerate() {
                matrix[(i, j)] = value;
            }
        }
        matrix
    }

    /// Get component names
    pub fn component_names(&self) -> Vec<String> {
        (1..=self.n_components())
            .map(|i| format!("PC{}", i))
            .collect()
    }

    /// Get summary statistics
    pub fn summary(&self) -> PcaSummary {
        PcaSummary {
            n_components: self.n_components(),
            n_observations: self.n_observations(),
            n_variables: self.n_variables(),
            total_variance_explained: self.cumulative_variance_ratio.last().copied().unwrap_or(0.0),
            component_names: self.component_names(),
            explained_variance_ratio: self.explained_variance_ratio.clone(),
        }
    }
}

/// Summary statistics for PCA results
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PcaSummary {
    /// Number of components
    pub n_components: usize,
    /// Number of observations
    pub n_observations: usize,
    /// Number of variables
    pub n_variables: usize,
    /// Total variance explained
    pub total_variance_explained: f64,
    /// Component names
    pub component_names: Vec<String>,
    /// Explained variance ratio for each component
    pub explained_variance_ratio: Vec<f64>,
}

impl std::fmt::Display for PcaSummary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "PCA Summary")?;
        writeln!(f, "Components: {}", self.n_components)?;
        writeln!(f, "Observations: {}", self.n_observations)?;
        writeln!(f, "Variables: {}", self.n_variables)?;
        writeln!(f, "Total Variance Explained: {:.2}%", self.total_variance_explained * 100.0)?;
        writeln!(f, "\nVariance Explained by Component:")?;

        for (i, &ratio) in self.explained_variance_ratio.iter().enumerate() {
            writeln!(f, "  PC{}: {:.2}%", i + 1, ratio * 100.0)?;
        }

        Ok(())
    }
}

/// Convenience function to perform PCA on confound variables
pub fn pca_confounds(
    confounds: HashMap<String, Vec<f64>>,
    n_components: Option<usize>,
    variance_threshold: Option<f64>,
) -> Result<PcaResult> {
    let processor = PcaProcessor::from_confound_map(confounds)?;

    match (n_components, variance_threshold) {
        (Some(n), None) => processor.compute_n_components(n),
        (None, Some(threshold)) => processor.compute_variance_threshold(threshold),
        (Some(n), Some(threshold)) => {
            let result = processor.compute_variance_threshold(threshold)?;
            if result.n_components() > n {
                processor.compute_n_components(n)
            } else {
                Ok(result)
            }
        }
        (None, None) => processor.compute(),
    }
}

