    #[test]
    fn test_pca_computation() {
        let variables = vec![
            ("var1".to_string(), vec![1.0, 2.0, 3.0, 4.0]),
            ("var2".to_string(), vec![2.0, 4.0, 6.0, 8.0]),
            ("var3".to_string(), vec![1.0, 3.0, 5.0, 7.0]),
        ];

        let processor = PcaProcessor::from_variables(variables).unwrap();
        let result = processor.compute().unwrap();

        assert_eq!(result.n_components(), 3);
        assert_eq!(result.n_observations(), 4);
        assert_eq!(result.n_variables(), 3);

        // Check that explained variance ratios sum to approximately 1
        let total_variance: f64 = result.explained_variance_ratio.iter().sum();
        assert_relative_eq!(total_variance, 1.0, epsilon = 1e-10);

        // Check that explained variance is in descending order
        for i in 1..result.explained_variance.len() {
            assert!(result.explained_variance[i-1] >= result.explained_variance[i]);
        }
    }

