        let processor = PcaProcessor::from_variables(variables).unwrap();
        let result = processor.compute_variance_threshold(0.95).unwrap();

        assert!(result.cumulative_variance_ratio.last().unwrap() >= &0.95);
    }

    #[test]
    fn test_pca_confounds_function() {
        let mut confounds = HashMap::new();
        confounds.insert("CSF".to_string(), vec![0.1, 0.2, 0.3, 0.4]);
        confounds.insert("WhiteMatter".to_string(), vec![0.5, 0.6, 0.7, 0.8]);
        confounds.insert("GlobalSignal".to_string(), vec![100.0, 101.0, 102.0, 103.0]);

        let result = pca_confounds(confounds, Some(2), None).unwrap();

        assert_eq!(result.n_components(), 2);
        assert_eq!(result.n_observations(), 4);
        assert_eq!(result.n_variables(), 3);
    }

    #[test]
    fn test_pca_result_matrices() {
        let variables = vec![
            ("var1".to_string(), vec![1.0, 2.0, 3.0]),
            ("var2".to_string(), vec![2.0, 4.0, 6.0]),
        ];

        let processor = PcaProcessor::from_variables(variables).unwrap();
        let result = processor.compute().unwrap();

        let scores_matrix = result.scores_matrix();
        let loadings_matrix = result.loadings_matrix();

        assert_eq!(scores_matrix.nrows(), result.n_observations());
        assert_eq!(scores_matrix.ncols(), result.n_components());
        assert_eq!(loadings_matrix.nrows(), result.n_variables());
        assert_eq!(loadings_matrix.ncols(), result.n_components());
    }

    #[test]
    fn test_pca_summary() {
        let variables = vec![
            ("var1".to_string(), vec![1.0, 2.0, 3.0, 4.0]),
            ("var2".to_string(), vec![2.0, 4.0, 6.0, 8.0]),
        ];

        let processor = PcaProcessor::from_variables(variables).unwrap();
        let result = processor.compute().unwrap();
        let summary = result.summary();

        assert_eq!(summary.n_components, 2);
        assert_eq!(summary.n_observations, 4);
        assert_eq!(summary.n_variables, 2);
        assert_eq!(summary.component_names, vec!["PC1", "PC2"]);
    }

    #[test]
    fn test_pca_error_handling() {
        // Test mismatched variable lengths
        let variables = vec![
            ("var1".to_string(), vec![1.0, 2.0, 3.0]),
            ("var2".to_string(), vec![2.0, 4.0]), // Different length
        ];

        let result = PcaProcessor::from_variables(variables);
        assert!(result.is_err());

        // Test zero variance
        let variables = vec![
            ("var1".to_string(), vec![1.0, 1.0, 1.0]), // Zero variance
            ("var2".to_string(), vec![2.0, 4.0, 6.0]),
        ];

        let processor = PcaProcessor::from_variables(variables).unwrap();
        let result = processor.compute();
        assert!(result.is_err());
    }
}

