                    }
                    if let Some(ses) = file.entities.get("ses") {
                        confound_data.session = Some(ses.clone());
                    }
                    if let Some(task) = file.entities.get("task") {
                        confound_data.task = Some(task.clone());
                    }
                    if let Some(run) = file.entities.get("run") {
                        confound_data.run = Some(run.clone());
                    }
                    all_confounds.push(confound_data);
                }
                Err(e) => {
                    eprintln!("Warning: Failed to read confound file {:?}: {}", file.path, e);
                }
            }
        }

        Ok(all_confounds)
    }

    /// Read confounds with PCA reduction
    pub fn read_confounds_with_pca(&self, n_components: usize) -> Result<Vec<crate::io::ConfoundsData>> {
        use crate::io::{ConfoundsReader, BidsReader};

        let confound_files = self.search_files()
            .entity("desc", "confounds")
            .suffix("timeseries")
            .extension("tsv")
            .execute()?;

        let reader = ConfoundsReader::new().with_pca(n_components);
        let mut all_confounds = Vec::new();

