//! Sidecar JSON file reading and processing
//!
//! This module provides functionality for reading BIDS sidecar JSON files
//! that contain metadata for neuroimaging data.

use std::path::Path;
use std::collections::HashMap;
use serde::{Deserialize, Serialize};
use serde_json::Value;

use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::io::utils;
use super::BidsReader;

/// Sidecar JSON data structure
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct SidecarData {
    /// Raw JSON data
    pub data: HashMap<String, Value>,
    /// Subject ID (filled by BidsProject when reading)
    #[serde(skip_serializing_if = "String::is_empty", default)]
    pub subject: String,
    /// Session ID (optional)
    #[serde(skip_serializing_if = "Option::is_none", default)]
    pub session: Option<String>,
    /// Task name (optional)
    #[serde(skip_serializing_if = "Option::is_none", default)]
    pub task: Option<String>,
    /// Run number (optional)
    #[serde(skip_serializing_if = "Option::is_none", default)]
    pub run: Option<String>,
    /// File suffix (e.g., "bold", "T1w")
    #[serde(skip_serializing_if = "String::is_empty", default)]
    pub suffix: String,
}

/// Sidecar file reader
pub struct SidecarReader {
    /// Whether to validate required fields
    validate_required: bool,
}

impl SidecarReader {
    /// Create a new sidecar reader
    pub fn new() -> Self {
        Self {
            validate_required: true,
        }
    }

    /// Set whether to validate required fields
    pub fn validate_required(mut self, validate: bool) -> Self {
        self.validate_required = validate;
        self
    }

    /// Validate functional MRI sidecar
    fn validate_func_sidecar(&self, data: &SidecarData) -> Result<()> {
        // Check for RepetitionTime
        if !data.has_field("RepetitionTime") {
            return Err(BidsError::validation_error(
                "Functional sidecar missing RepetitionTime",
                Some("RepetitionTime".to_string()),
            ));
        }

        // Check for TaskName
        if !data.has_field("TaskName") {
            return Err(BidsError::validation_error(
                "Functional sidecar missing TaskName",
                Some("TaskName".to_string()),
            ));
        }

        Ok(())
    }

    /// Validate anatomical MRI sidecar
    fn validate_anat_sidecar(&self, _data: &SidecarData) -> Result<()> {
        // Anatomical scans have fewer required fields
        // This is a placeholder for future validation
        Ok(())
    }
}

impl Default for SidecarReader {
    fn default() -> Self {
        Self::new()
    }
}

impl BidsReader<SidecarData> for SidecarReader {
    fn read(&self, file: &BidsFile) -> Result<SidecarData> {
        if !file.is_sidecar() {
            return Err(BidsError::validation_error(
                "File is not a sidecar JSON file",
                Some("extension".to_string()),
            ));
        }

        let data = self.read_path(&file.path)?;

        if self.validate_required {
            // Validate based on file type
            if file.is_func() {
                self.validate_func_sidecar(&data)?;
            } else if file.is_anat() {
                self.validate_anat_sidecar(&data)?;
            }
        }

        Ok(data)
    }

    fn read_path(&self, path: &Path) -> Result<SidecarData> {
        if !utils::is_readable(path) {
            return Err(BidsError::file_not_found(path));
        }

        let content = utils::read_text_file(path)?;
        let data: HashMap<String, Value> = serde_json::from_str(&content)?;

        Ok(SidecarData { 
            data,
            subject: String::new(),
            session: None,
            task: None,
            run: None,
            suffix: String::new(),
        })
    }
}

impl SidecarData {
    /// Create a new empty SidecarData
    pub fn new() -> Self {
        Self {
            data: HashMap::new(),
            subject: String::new(),
            session: None,
            task: None,
            run: None,
            suffix: String::new(),
        }
    }

    /// Create SidecarData from a HashMap
    pub fn from_map(data: HashMap<String, Value>) -> Self {
        Self { 
            data,
            subject: String::new(),
            session: None,
            task: None,
            run: None,
            suffix: String::new(),
        }
    }

    /// Check if a field exists
    pub fn has_field(&self, field: &str) -> bool {
        self.data.contains_key(field)
    }

    /// Get a field value
    pub fn get_field(&self, field: &str) -> Option<&Value> {
        self.data.get(field)
    }

    /// Get a field value as a specific type
    pub fn get_field_as<T>(&self, field: &str) -> Option<T>
    where
        T: for<'de> Deserialize<'de>,
    {
        self.data.get(field).and_then(|v| {
            serde_json::from_value(v.clone()).ok()
        })
    }

    /// Get RepetitionTime (TR) for functional scans
    pub fn repetition_time(&self) -> Option<f64> {
        self.get_field_as("RepetitionTime")
    }

    /// Get TaskName for functional scans
    pub fn task_name(&self) -> Option<String> {
        self.get_field_as("TaskName")
    }

    /// Get EchoTime for MRI scans
    pub fn echo_time(&self) -> Option<f64> {
        self.get_field_as("EchoTime")
    }

    /// Get FlipAngle for MRI scans
    pub fn flip_angle(&self) -> Option<f64> {
        self.get_field_as("FlipAngle")
    }

    /// Get SliceTiming for functional scans
    pub fn slice_timing(&self) -> Option<Vec<f64>> {
        self.get_field_as("SliceTiming")
    }

    /// Get NumberOfVolumesDiscardedByUser
    pub fn volumes_discarded(&self) -> Option<i32> {
        self.get_field_as("NumberOfVolumesDiscardedByUser")
    }

    /// Get all field names
    pub fn field_names(&self) -> Vec<String> {
        self.data.keys().cloned().collect()
    }

    /// Get field as string
    pub fn get_string(&self, field: &str) -> Option<String> {
        self.data.get(field).and_then(|v| match v {
            Value::String(s) => Some(s.clone()),
            Value::Number(n) => Some(n.to_string()),
            Value::Bool(b) => Some(b.to_string()),
            _ => None,
        })
    }

    /// Get field as number
    pub fn get_number(&self, field: &str) -> Option<f64> {
        self.data.get(field).and_then(|v| match v {
            Value::Number(n) => n.as_f64(),
            Value::String(s) => s.parse().ok(),
            _ => None,
        })
    }

    /// Get field as boolean
    pub fn get_bool(&self, field: &str) -> Option<bool> {
        self.data.get(field).and_then(|v| match v {
            Value::Bool(b) => Some(*b),
            Value::String(s) => match s.to_lowercase().as_str() {
                "true" | "1" | "yes" => Some(true),
                "false" | "0" | "no" => Some(false),
                _ => None,
            },
            Value::Number(n) => n.as_f64().map(|n| n != 0.0),
            _ => None,
        })
    }

    /// Get field as array of strings
    pub fn get_string_array(&self, field: &str) -> Option<Vec<String>> {
        self.data.get(field).and_then(|v| match v {
            Value::Array(arr) => {
                let strings: Result<Vec<String>, _> = arr.iter()
                    .map(|item| match item {
                        Value::String(s) => Ok(s.clone()),
                        _ => Err(()),
                    })
                    .collect();
                strings.ok()
            },
            _ => None,
        })
    }

    /// Get field as array of numbers
    pub fn get_number_array(&self, field: &str) -> Option<Vec<f64>> {
        self.data.get(field).and_then(|v| match v {
            Value::Array(arr) => {
                let numbers: std::result::Result<Vec<f64>, ()> = arr.iter()
                    .map(|item| match item {
                        Value::Number(n) => n.as_f64().ok_or(()),
                        _ => Err(()),
                    })
                    .collect();
                numbers.ok()
            },
            _ => None,
        })
    }

    /// Check if this is a functional scan sidecar
    pub fn is_func_sidecar(&self) -> bool {
        self.has_field("RepetitionTime") || self.has_field("TaskName")
    }

    /// Check if this is an anatomical scan sidecar
    pub fn is_anat_sidecar(&self) -> bool {
        // Anatomical scans often have these fields
        self.has_field("MagneticFieldStrength") && 
        !self.has_field("RepetitionTime") && 
        !self.has_field("TaskName")
    }

    /// Get summary information
    pub fn summary(&self) -> SidecarSummary {
        SidecarSummary {
            n_fields: self.data.len(),
            field_names: self.field_names(),
            is_func: self.is_func_sidecar(),
            is_anat: self.is_anat_sidecar(),
            repetition_time: self.repetition_time(),
            task_name: self.task_name(),
        }
    }
}

impl Default for SidecarData {
    fn default() -> Self {
        Self::new()
    }
}

/// Summary information for sidecar data
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SidecarSummary {
    /// Number of fields
    pub n_fields: usize,
    /// Field names
    pub field_names: Vec<String>,
    /// Whether this is a functional scan sidecar
    pub is_func: bool,
    /// Whether this is an anatomical scan sidecar
    pub is_anat: bool,
    /// Repetition time (if functional)
    pub repetition_time: Option<f64>,
    /// Task name (if functional)
    pub task_name: Option<String>,
}

impl std::fmt::Display for SidecarSummary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        writeln!(f, "Sidecar Summary")?;
        writeln!(f, "Fields: {}", self.n_fields)?;
        writeln!(f, "Type: {}", if self.is_func { "Functional" } else if self.is_anat { "Anatomical" } else { "Unknown" })?;

        if let Some(tr) = self.repetition_time {
            writeln!(f, "RepetitionTime: {:.3} s", tr)?;
        }

        if let Some(task) = &self.task_name {
            writeln!(f, "TaskName: {}", task)?;
        }

        Ok(())
    }
}

/// Convenience function to read sidecar from a path
pub fn read_sidecar<P: AsRef<Path>>(path: P) -> Result<SidecarData> {
    let reader = SidecarReader::new();
    reader.read_path(path.as_ref())
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_func_sidecar() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("sub-01_task-test_bold.json");

        let sidecar_data = serde_json::json!({
            "RepetitionTime": 2.0,
            "TaskName": "test",
            "EchoTime": 0.03,
            "FlipAngle": 90,
            "SliceTiming": [0.0, 0.5, 1.0, 1.5]
        });

        fs::write(&file_path, serde_json::to_string_pretty(&sidecar_data)?)?;
        Ok((temp_dir, file_path))
    }

    fn create_test_anat_sidecar() -> Result<(TempDir, std::path::PathBuf)> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("sub-01_T1w.json");

        let sidecar_data = serde_json::json!({
            "MagneticFieldStrength": 3.0,
            "EchoTime": 0.004,
            "FlipAngle": 8,
            "InversionTime": 1.0
        });

        fs::write(&file_path, serde_json::to_string_pretty(&sidecar_data)?)?;
        Ok((temp_dir, file_path))
    }

    #[test]
    fn test_read_func_sidecar() -> Result<()> {
        let (_temp_dir, file_path) = create_test_func_sidecar()?;

        let sidecar = read_sidecar(&file_path)?;

        assert_eq!(sidecar.repetition_time(), Some(2.0));
        assert_eq!(sidecar.task_name(), Some("test".to_string()));
        assert_eq!(sidecar.echo_time(), Some(0.03));
        assert_eq!(sidecar.flip_angle(), Some(90.0));
        assert!(sidecar.is_func_sidecar());
        assert!(!sidecar.is_anat_sidecar());

        Ok(())
    }

    #[test]
    fn test_read_anat_sidecar() -> Result<()> {
        let (_temp_dir, file_path) = create_test_anat_sidecar()?;

        let sidecar = read_sidecar(&file_path)?;

        assert_eq!(sidecar.repetition_time(), None);
        assert_eq!(sidecar.task_name(), None);
        assert_eq!(sidecar.get_number("MagneticFieldStrength"), Some(3.0));
        assert!(!sidecar.is_func_sidecar());
        assert!(sidecar.is_anat_sidecar());

        Ok(())
    }

    #[test]
    fn test_sidecar_field_access() -> Result<()> {
        let (_temp_dir, file_path) = create_test_func_sidecar()?;
        let sidecar = read_sidecar(&file_path)?;

        // Test different field access methods
        assert_eq!(sidecar.get_number("RepetitionTime"), Some(2.0));
        assert_eq!(sidecar.get_string("TaskName"), Some("test".to_string()));
        assert_eq!(sidecar.get_number_array("SliceTiming"), Some(vec![0.0, 0.5, 1.0, 1.5]));

        // Test non-existent field
        assert_eq!(sidecar.get_string("NonExistent"), None);

        Ok(())
    }

    #[test]
    fn test_sidecar_validation() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("invalid_func.json");

        // Create invalid functional sidecar (missing RepetitionTime)
        let invalid_data = serde_json::json!({
            "TaskName": "test"
        });

        fs::write(&file_path, serde_json::to_string_pretty(&invalid_data)?)?;

        let reader = SidecarReader::new().validate_required(true);
        let result = reader.read_path(&file_path);

        // Should fail validation
        assert!(result.is_err());

        Ok(())
    }

    #[test]
    fn test_sidecar_summary() -> Result<()> {
        let (_temp_dir, file_path) = create_test_func_sidecar()?;
        let sidecar = read_sidecar(&file_path)?;

        let summary = sidecar.summary();

        assert_eq!(summary.n_fields, 5);
        assert!(summary.is_func);
        assert!(!summary.is_anat);
        assert_eq!(summary.repetition_time, Some(2.0));
        assert_eq!(summary.task_name, Some("test".to_string()));

        Ok(())
    }

    #[test]
    fn test_type_conversion() -> Result<()> {
        let temp_dir = TempDir::new()?;
        let file_path = temp_dir.path().join("conversion_test.json");

        let test_data = serde_json::json!({
            "StringField": "test",
            "NumberField": 42.5,
            "BoolField": true,
            "StringNumberField": "123.45",
            "StringBoolField": "true"
        });

        fs::write(&file_path, serde_json::to_string_pretty(&test_data)?)?;
        let sidecar = read_sidecar(&file_path)?;

        assert_eq!(sidecar.get_string("StringField"), Some("test".to_string()));
        assert_eq!(sidecar.get_number("NumberField"), Some(42.5));
        assert_eq!(sidecar.get_bool("BoolField"), Some(true));
        assert_eq!(sidecar.get_number("StringNumberField"), Some(123.45));
        assert_eq!(sidecar.get_bool("StringBoolField"), Some(true));

        Ok(())
    }

    #[test]
    fn test_slice_timing() -> Result<()> {
        let (_temp_dir, file_path) = create_test_func_sidecar()?;
        let sidecar = read_sidecar(&file_path)?;

        let slice_timing = sidecar.slice_timing();
        assert_eq!(slice_timing, Some(vec![0.0, 0.5, 1.0, 1.5]));

        Ok(())
    }
}

