//! Subject-specific interface for BIDS data access
//!
//! This module provides a convenient interface for accessing all data
//! related to a specific subject, similar to R's bids_subject functionality.

use std::collections::HashMap;
use crate::{BidsProject, BidsFile, EventData, ConfoundsData, Result, BidsError};

/// Interface for accessing subject-specific data
pub struct SubjectInterface<'a> {
    project: &'a BidsProject,
    subject_id: String,
}

/// Summary statistics for a subject
#[derive(Debug, Clone)]
pub struct SubjectSummary {
    pub subject_id: String,
    pub n_anatomical_scans: usize,
    pub n_functional_scans: usize,
    pub n_tasks: usize,
    pub tasks: Vec<String>,
    pub n_runs: HashMap<String, usize>,
    pub n_sessions: usize,
    pub sessions: Vec<String>,
    pub has_derivatives: bool,
}

impl<'a> SubjectInterface<'a> {
    /// Create a new subject interface
    pub(crate) fn new(project: &'a BidsProject, subject_id: String) -> Self {
        Self {
            project,
            subject_id,
        }
    }

    /// Get all anatomical scans for this subject
    pub fn anatomical_scans(&self) -> Result<Vec<BidsFile>> {
        self.project.search_files()
            .subject(&self.subject_id)
            .datatype("anat")
            .collect()
    }

    /// Get all functional scans for this subject
    pub fn functional_scans(&self) -> Result<Vec<BidsFile>> {
        self.project.search_files()
            .subject(&self.subject_id)
            .datatype("func")
            .suffix("bold")
            .collect()
    }

    /// Get functional scans for a specific session
    pub fn functional_scans_session(&self, session: &str) -> Result<Vec<BidsFile>> {
        self.project.search_files()
            .subject(&self.subject_id)
            .session(session)
            .datatype("func")
            .suffix("bold")
            .collect()
    }

    /// Get functional scans for a specific task
    pub fn functional_scans_task(&self, task: &str) -> Result<Vec<BidsFile>> {
        self.project.search_files()
            .subject(&self.subject_id)
            .task(task)
            .datatype("func")
            .suffix("bold")
            .collect()
    }

    /// Get all event files for this subject
    pub fn events(&self) -> Result<Vec<EventData>> {
        self.project.read_events()
            .subject(&self.subject_id)
            .collect()
    }

    /// Get all confound files for this subject
    pub fn confounds(&self) -> Result<Vec<ConfoundsData>> {
        self.project.read_confounds()
            .subject(&self.subject_id)
            .collect()
    }

    /// Get all preprocessed scans (derivatives) for this subject
    pub fn preprocessed_scans(&self) -> Result<Vec<BidsFile>> {
        self.project.search_files()
            .subject(&self.subject_id)
            .in_derivatives(true)
            .suffix("bold")
            .collect()
    }

    /// Get all brain masks for this subject
    pub fn brain_masks(&self) -> Result<Vec<BidsFile>> {
        self.project.search_files()
            .subject(&self.subject_id)
            .in_derivatives(true)
            .suffix("mask")
            .collect()
    }

    /// Get all unique tasks for this subject
    pub fn tasks(&self) -> Result<Vec<String>> {
        let func_scans = self.functional_scans()?;
        let mut tasks = Vec::new();

        for scan in func_scans {
            if let Some(task) = scan.entities.get("task") {
                if !tasks.contains(task) {
                    tasks.push(task.clone());
                }
            }
        }

        tasks.sort();
        Ok(tasks)
    }

    /// Get all unique sessions for this subject
    pub fn sessions(&self) -> Result<Vec<String>> {
        let all_files = self.project.search_files()
            .subject(&self.subject_id)
            .collect()?;

        let mut sessions = Vec::new();

        for file in all_files {
            if let Some(session) = file.entities.get("ses") {
                if !sessions.contains(session) {
                    sessions.push(session.clone());
                }
            }
        }

        sessions.sort();
        Ok(sessions)
    }

    /// Get summary statistics for this subject
    pub fn summary(&self) -> Result<SubjectSummary> {
        let anat_scans = self.anatomical_scans()?;
        let func_scans = self.functional_scans()?;
        let tasks = self.tasks()?;
        let sessions = self.sessions()?;

        // Count runs per task
        let mut n_runs = HashMap::new();
        for scan in &func_scans {
            if let Some(task) = scan.entities.get("task") {
                let count = n_runs.entry(task.clone()).or_insert(0);
                *count += 1;
            }
        }

        // Check for derivatives
        let has_derivatives = !self.preprocessed_scans()?.is_empty();

        Ok(SubjectSummary {
            subject_id: self.subject_id.clone(),
            n_anatomical_scans: anat_scans.len(),
            n_functional_scans: func_scans.len(),
            n_tasks: tasks.len(),
            tasks,
            n_runs,
            n_sessions: sessions.len(),
            sessions,
            has_derivatives,
        })
    }
}

impl BidsProject {
    /// Get a subject-specific interface
    pub fn subject(&self, subject_id: &str) -> Result<SubjectInterface<'_>> {
        // Verify subject exists
        let participants = self.participants();
        if !participants.contains(&subject_id.to_string()) {
            return Err(BidsError::InvalidSubject(subject_id.to_string()));
        }

        Ok(SubjectInterface::new(self, subject_id.to_string()))
    }
}

