//! fMRIPrep derivatives support
//!
//! This module provides functionality for working with fMRIPrep derivatives,
//! including preprocessed functional scans and associated metadata.

use std::path::PathBuf;
use crate::error::{BidsError, Result};
use crate::file::BidsFile;
use crate::project::BidsProject;
use crate::search::SearchBuilder;

/// fMRIPrep derivatives handler
pub struct DerivativesHandler<'a> {
    /// Reference to the BIDS project
    project: &'a BidsProject,
    /// Path to the derivatives directory
    derivatives_path: PathBuf,
}

impl<'a> DerivativesHandler<'a> {
    /// Create a new derivatives handler
    pub fn new(project: &'a BidsProject) -> Result<Self> {
        let derivatives_path = project.derivatives_path.as_ref().ok_or_else(|| {
            BidsError::unsupported_feature("No derivatives directory found")
        })?;

        Ok(Self {
            project,
            derivatives_path: derivatives_path.clone(),
        })
    }

    /// Find preprocessed functional scans
    pub fn preproc_scans(&self) -> SearchBuilder<'_> {
        self.project
            .search()
            .derivatives(true)
            .desc("preproc")
            .suffix("bold")
    }

    /// Find confound files
    pub fn confound_files(&self) -> SearchBuilder<'_> {
        self.project
            .search()
            .derivatives(true)
            .desc("confounds")
            .suffix("regressors")
    }

    /// Find brain mask files
    pub fn brain_masks(&self) -> SearchBuilder<'_> {
        self.project
            .search()
            .derivatives(true)
            .desc("brain")
            .suffix("mask")
    }

    /// Check if derivatives are available
    pub fn has_derivatives(&self) -> bool {
        self.derivatives_path.exists()
    }

    /// Get derivatives path
    pub fn derivatives_path(&self) -> &PathBuf {
        &self.derivatives_path
    }

    /// Find all derivative files for a subject
    pub fn subject_derivatives(&self, subject: &str) -> Result<Vec<BidsFile>> {
        self.project
            .search()
            .derivatives(true)
            .subject(subject)
            .collect()
    }

    /// Find specific derivative types
    pub fn find_derivatives_by_type(&self, derivative_type: &str) -> Result<Vec<BidsFile>> {
        match derivative_type {
            "preproc" => self.preproc_scans().collect(),
            "confounds" => self.confound_files().collect(),
            "masks" => self.brain_masks().collect(),
            _ => Err(BidsError::unsupported_feature(
                format!("Unknown derivative type: {}", derivative_type)
            )),
        }
    }
}

/// fMRIPrep space definitions
pub struct FmriprepSpaces;

impl FmriprepSpaces {
    /// Standard MNI space
    pub const MNI152_NLIN2009C_ASYM: &'static str = "MNI152NLin2009cAsym";

    /// Standard MNI space (6th generation)
    pub const MNI152_NLIN6_ASYM: &'static str = "MNI152NLin6Asym";

    /// Native space
    pub const NATIVE: &'static str = "T1w";

    /// fsnative space
    pub const FS_NATIVE: &'static str = "fsnative";

    /// Check if a space is a standard template
    pub fn is_standard_space(space: &str) -> bool {
        matches!(space, 
            Self::MNI152_NLIN2009C_ASYM | 
            Self::MNI152_NLIN6_ASYM
        )
    }

    /// Check if a space is native
    pub fn is_native_space(space: &str) -> bool {
        matches!(space, Self::NATIVE | Self::FS_NATIVE)
    }

    /// Get all available standard spaces
    pub fn standard_spaces() -> Vec<&'static str> {
        vec![
            Self::MNI152_NLIN2009C_ASYM,
            Self::MNI152_NLIN6_ASYM,
        ]
    }
}

/// fMRIPrep derivative types
pub struct FmriprepDerivatives;

impl FmriprepDerivatives {
    /// Preprocessed BOLD files
    pub const PREPROC_BOLD: &'static str = "preproc";

    /// Confound regressors
    pub const CONFOUNDS: &'static str = "confounds";

    /// Brain masks
    pub const BRAIN_MASK: &'static str = "brain";

    /// Tissue probability maps
    pub const TISSUE_PROB: &'static str = "probseg";

    /// Transform files
    pub const TRANSFORMS: &'static str = "xfm";

    /// Get all derivative types
    pub fn all_types() -> Vec<&'static str> {
        vec![
            Self::PREPROC_BOLD,
            Self::CONFOUNDS,
            Self::BRAIN_MASK,
            Self::TISSUE_PROB,
            Self::TRANSFORMS,
        ]
    }
}

/// Convenience functions for working with derivatives
pub mod utils {
    use super::*;

    /// Find preprocessed scans for a subject in a specific space
    pub fn find_preproc_scans_in_space(
        project: &BidsProject,
        subject: &str,
        space: &str,
    ) -> Result<Vec<BidsFile>> {
        project
            .search()
            .derivatives(true)
            .subject(subject)
            .space(space)
            .desc("preproc")
            .suffix("bold")
            .collect()
    }

    /// Find confound files for a subject
    pub fn find_confounds_for_subject(
        project: &BidsProject,
        subject: &str,
    ) -> Result<Vec<BidsFile>> {
        project
            .search()
            .derivatives(true)
            .subject(subject)
            .desc("confounds")
            .collect()
    }

    /// Find brain mask for a subject in a specific space
    pub fn find_brain_mask_for_subject(
        project: &BidsProject,
        subject: &str,
        space: &str,
    ) -> Result<Option<BidsFile>> {
        project
            .search()
            .derivatives(true)
            .subject(subject)
            .space(space)
            .desc("brain")
            .suffix("mask")
            .first()
    }

    /// Check if a subject has derivatives in a specific space
    pub fn has_derivatives_in_space(
        project: &BidsProject,
        subject: &str,
        space: &str,
    ) -> Result<bool> {
        let files = project
            .search()
            .derivatives(true)
            .subject(subject)
            .space(space)
            .collect()?;

        Ok(!files.is_empty())
    }
}

// TODO: Phase 3.2 - Preprocessed data handling
// The following functionality requires neuroimaging I/O libraries (like NIfTI readers)
// which are beyond the current scope. These would be implemented with crates like:
// - nifti-rs for reading NIfTI files
// - ndarray for handling multi-dimensional arrays
//
// Placeholder for future implementation:
// - read_preproc_scans() - Read actual preprocessed BOLD data
// - create_brain_mask() - Generate binary brain masks from probability maps
// - load_preprocessed_timeseries() - Load 4D fMRI data
//
// These functions are marked as optional in feature_parity.md due to the
// neuroim2 dependency requirement in the original R package.

#[cfg(test)]
mod tests {
    use super::*;
    use crate::project::BidsProject;
    use tempfile::TempDir;
    use std::fs;

    fn create_test_project_with_derivatives() -> Result<(TempDir, BidsProject)> {
        let temp_dir = TempDir::new()?;
        let root = temp_dir.path();

        // Create minimal BIDS structure
        let participants_content = "participant_id\nsub-01\n";
        fs::write(root.join("participants.tsv"), participants_content)?;

        let dataset_description = serde_json::json!({
            "Name": "Test Dataset",
            "BIDSVersion": "1.8.0"
        });
        fs::write(
            root.join("dataset_description.json"),
            serde_json::to_string_pretty(&dataset_description)?,
        )?;

        // Create derivatives directory
        let derivatives_dir = root.join("derivatives").join("fmriprep");
        fs::create_dir_all(&derivatives_dir)?;

        // Create subject directory
        fs::create_dir_all(root.join("sub-01"))?;

        let project = BidsProject::with_derivatives(root, Some(derivatives_dir))?;
        Ok((temp_dir, project))
    }

    #[test]
    fn test_derivatives_handler_creation() -> Result<()> {
        let (_temp_dir, project) = create_test_project_with_derivatives()?;

        if project.has_derivatives {
            let handler = DerivativesHandler::new(&project)?;
            assert!(handler.has_derivatives());
        }

        Ok(())
    }

    #[test]
    fn test_fmriprep_spaces() {
        assert!(FmriprepSpaces::is_standard_space(FmriprepSpaces::MNI152_NLIN2009C_ASYM));
        assert!(FmriprepSpaces::is_native_space(FmriprepSpaces::NATIVE));
        assert!(!FmriprepSpaces::is_standard_space(FmriprepSpaces::NATIVE));
        assert!(!FmriprepSpaces::is_native_space(FmriprepSpaces::MNI152_NLIN2009C_ASYM));
    }

    #[test]
    fn test_fmriprep_derivatives() {
        let all_types = FmriprepDerivatives::all_types();
        assert!(all_types.contains(&FmriprepDerivatives::PREPROC_BOLD));
        assert!(all_types.contains(&FmriprepDerivatives::CONFOUNDS));
        assert!(all_types.contains(&FmriprepDerivatives::BRAIN_MASK));
    }

    #[test]
    fn test_derivatives_utils() -> Result<()> {
        let (_temp_dir, project) = create_test_project_with_derivatives()?;

        // Test finding preprocessed scans (should be empty for test project)
        let preproc_scans = utils::find_preproc_scans_in_space(
            &project,
            "01",
            FmriprepSpaces::MNI152_NLIN2009C_ASYM,
        )?;
        assert!(preproc_scans.is_empty());

        // Test finding confounds (should be empty for test project)
        let confounds = utils::find_confounds_for_subject(&project, "01")?;
        assert!(confounds.is_empty());

        // Test finding brain mask (should be None for test project)
        let brain_mask = utils::find_brain_mask_for_subject(
            &project,
            "01",
            FmriprepSpaces::MNI152_NLIN2009C_ASYM,
        )?;
        assert!(brain_mask.is_none());

        Ok(())
    }

    #[test]
    fn test_derivatives_handler_searches() -> Result<()> {
        let (_temp_dir, project) = create_test_project_with_derivatives()?;

        if project.has_derivatives {
            let handler = DerivativesHandler::new(&project)?;

            // Test search builders (should return empty for test project)
            let preproc_files = handler.preproc_scans().collect()?;
            assert!(preproc_files.is_empty());

            let confound_files = handler.confound_files().collect()?;
            assert!(confound_files.is_empty());

            let mask_files = handler.brain_masks().collect()?;
            assert!(mask_files.is_empty());
        }

        Ok(())
    }
}

