//! DataFrame support for BIDS data using Polars
//!
//! This module provides high-performance dataframe functionality for BIDS data
//! when the `dataframes` feature is enabled. It leverages the Polars library
//! for fast, memory-efficient operations on tabular data.
//!
//! # Features
//!
//! - High-performance CSV/TSV reading with Polars
//! - Direct integration with BIDS validation
//! - Lazy evaluation support
//! - Memory-efficient columnar operations
//!
//! # Usage
//!
//! Enable the `dataframes` feature in your `Cargo.toml`:
//!
//! ```toml
//! [dependencies]
//! bids-rust = { version = "0.1", features = ["dataframes"] }
//! ```
//!
//! Then use the dataframe-enabled functions:
//!
//! ```rust,no_run
//! use bids_rust::dataframes::{read_events_df, read_confounds_df};
//! use std::path::Path;
//!
//! # fn main() -> Result<(), Box<dyn std::error::Error>> {
//! // Read events into a Polars DataFrame
//! let events_df = read_events_df(Path::new("sub-01_task-rest_events.tsv"))?;
//! println!("Events shape: {:?}", events_df.shape());
//!
//! // Read confounds into a Polars DataFrame
//! let confounds_df = read_confounds_df(Path::new("sub-01_task-rest_desc-confounds_regressors.tsv"))?;
//! println!("Confounds shape: {:?}", confounds_df.shape());
//! # Ok(())
//! # }
//! ```

use std::path::Path;
use polars::prelude::*;

use crate::error::{BidsError, Result};
use crate::io::utils;

/// Re-export Polars DataFrame for convenience
pub use polars::prelude::DataFrame;

/// Read BIDS events file into a Polars DataFrame
///
/// This function reads a BIDS events TSV file directly into a Polars DataFrame,
/// providing high-performance access to event data with minimal memory overhead.
///
/// # Arguments
///
/// * `path` - Path to the events TSV file
///
/// # Returns
///
/// Returns a `Result<DataFrame>` containing the events data with columns:
/// - `onset`: Event onset times (f64)
/// - `duration`: Event durations (f64)
/// - `trial_type`: Event labels (String)
/// - Additional columns as found in the file
///
/// # Errors
///
/// Returns an error if:
/// - The file cannot be read or doesn't exist
/// - The file is not a valid TSV format
/// - Required BIDS columns (`onset`, `duration`) are missing
/// - The file fails BIDS validation
///
/// # Example
///
/// ```rust,no_run
/// use bids_rust::dataframes::read_events_df;
/// use std::path::Path;
///
/// # fn main() -> Result<(), Box<dyn std::error::Error>> {
/// let df = read_events_df(Path::new("sub-01_task-rest_events.tsv"))?;
/// 
/// // Access onset times
/// let onset_col = df.column("onset")?;
/// println!("First onset: {:?}", onset_col.get(0)?);
///
/// // Filter by trial type
/// let golden_trials = df.filter(&df.column("trial_type")?.equal("golden")?)?;
/// println!("Golden trials: {}", golden_trials.height());
/// # Ok(())
/// # }
/// ```
pub fn read_events_df(path: &Path) -> Result<DataFrame> {
    // Validate file exists and is readable
    if !utils::is_readable(path) {
        return Err(BidsError::file_not_found(path));
    }

    // Use Polars CsvReader for reading TSV files
    let df = CsvReader::new(std::fs::File::open(path)?)
        .with_delimiter(b'\t')
        .has_header(true)
        .finish()?;

    // Validate required BIDS columns are present
    validate_events_columns(&df)?;

    Ok(df)
}

/// Read BIDS confounds file into a Polars DataFrame
///
/// This function reads a BIDS confounds TSV file directly into a Polars DataFrame,
/// providing high-performance access to confound data with minimal memory overhead.
///
/// # Arguments
///
/// * `path` - Path to the confounds TSV file
///
/// # Returns
///
/// Returns a `Result<DataFrame>` containing the confounds data with all numeric
/// columns preserved as appropriate data types.
///
/// # Errors
///
/// Returns an error if:
/// - The file cannot be read or doesn't exist
/// - The file is not a valid TSV format
/// - The file fails BIDS validation
///
/// # Example
///
/// ```rust,no_run
/// use bids_rust::dataframes::read_confounds_df;
/// use std::path::Path;
///
/// # fn main() -> Result<(), Box<dyn std::error::Error>> {
/// let df = read_confounds_df(Path::new("sub-01_task-rest_desc-confounds_regressors.tsv"))?;
/// 
/// // Access motion parameters
/// if let Ok(trans_x) = df.column("trans_x") {
///     println!("Translation X range: {:?}", trans_x.min());
/// }
///
/// // Select motion columns
/// let motion_cols = ["trans_x", "trans_y", "trans_z", "rot_x", "rot_y", "rot_z"];
/// let motion_df = df.select(motion_cols)?;
/// println!("Motion data shape: {:?}", motion_df.shape());
/// # Ok(())
/// # }
/// ```
pub fn read_confounds_df(path: &Path) -> Result<DataFrame> {
    // Validate file exists and is readable
    if !utils::is_readable(path) {
        return Err(BidsError::file_not_found(path));
    }

    // Use Polars CsvReader for reading TSV files
    let df = CsvReader::new(std::fs::File::open(path)?)
        .with_delimiter(b'\t')
        .has_header(true)
        .finish()?;

    // Basic validation - confounds files should have at least one numeric column
    validate_confounds_columns(&df)?;

    Ok(df)
}

/// Create a lazy frame for efficient operations on large datasets
///
/// This function reads a BIDS TSV file into a lazy Polars DataFrame, which allows
/// for efficient chaining of operations without immediate execution.
///
/// # Arguments
///
/// * `path` - Path to the TSV file
///
/// # Returns
///
/// Returns a `Result<LazyFrame>` that can be used for lazy operations
///
/// # Example
///
/// ```rust,no_run
/// use bids_rust::dataframes::read_tsv_lazy;
/// use polars::prelude::*;
/// use std::path::Path;
///
/// # fn main() -> Result<(), Box<dyn std::error::Error>> {
/// let lazy_df = read_tsv_lazy(Path::new("sub-01_task-rest_events.tsv"))?;
/// 
/// // Chain operations efficiently
/// let result = lazy_df
///     .filter(col("trial_type").eq(lit("golden")))
///     .select([col("onset"), col("duration")])
///     .collect()?;
///
/// println!("Filtered events: {:?}", result.shape());
/// # Ok(())
/// # }
/// ```
pub fn read_tsv_lazy(path: &Path) -> Result<LazyFrame> {
    // Validate file exists and is readable
    if !utils::is_readable(path) {
        return Err(BidsError::file_not_found(path));
    }

    // Read into DataFrame first, then convert to lazy
    let df = CsvReader::from_path(path)?
        .with_delimiter(b'\t')
        .has_header(true)
        .finish()?;

    Ok(df.lazy())
}

/// Validate that required BIDS events columns are present
fn validate_events_columns(df: &DataFrame) -> Result<()> {
    let columns = df.get_column_names();

    // Check for required columns
    if !columns.iter().any(|col| col.as_str() == "onset") {
        return Err(BidsError::validation_error(
            "Missing required 'onset' column in events file",
            Some("onset".to_string()),
        ));
    }

    if !columns.iter().any(|col| col.as_str() == "duration") {
        return Err(BidsError::validation_error(
            "Missing required 'duration' column in events file",
            Some("duration".to_string()),
        ));
    }

    // Validate data types
    if let Ok(onset_col) = df.column("onset") {
        if !onset_col.dtype().is_primitive_numeric() {
            return Err(BidsError::validation_error(
                "Column 'onset' must be numeric",
                Some("onset".to_string()),
            ));
        }
    }

    if let Ok(duration_col) = df.column("duration") {
        if !duration_col.dtype().is_primitive_numeric() {
            return Err(BidsError::validation_error(
                "Column 'duration' must be numeric",
                Some("duration".to_string()),
            ));
        }
    }

    Ok(())
}

/// Validate that confounds DataFrame has expected structure
fn validate_confounds_columns(df: &DataFrame) -> Result<()> {
    let columns = df.get_column_names();

    if columns.is_empty() {
        return Err(BidsError::validation_error(
            "Confounds file has no columns",
            None,
        ));
    }

    // Check that at least some columns are numeric (confounds should be mostly numeric)
    let numeric_count = columns
        .iter()
        .filter_map(|name| df.column(name).ok())
        .filter(|col| col.dtype().is_primitive_numeric())
        .count();

    if numeric_count == 0 {
        return Err(BidsError::validation_error(
            "Confounds file has no numeric columns",
            None,
        ));
    }

    Ok(())
}

