use bids_rust::{BidsProject, Result};
use std::path::Path;
use tempfile::TempDir;
use std::fs;

fn main() -> Result<()> {
    println!("Testing basic BIDS functionality...");

    // Create a minimal test BIDS dataset
    let temp_dir = TempDir::new()?;
    let root = temp_dir.path();

    // Create required BIDS files
    let participants_content = "participant_id\tsex\tage\nsub-01\tF\t25\nsub-02\tM\t30\n";
    fs::write(root.join("participants.tsv"), participants_content)?;

    let dataset_description = serde_json::json!({
        "Name": "Test Dataset",
        "BIDSVersion": "1.8.0",
        "Description": "A test BIDS dataset for verifying functionality"
    });
    fs::write(
        root.join("dataset_description.json"),
        serde_json::to_string_pretty(&dataset_description)?,
    )?;

    // Create subject directories
    fs::create_dir_all(root.join("sub-01").join("func"))?;
    fs::create_dir_all(root.join("sub-02").join("func"))?;

    // Create some test functional files
    fs::File::create(root.join("sub-01").join("func").join("sub-01_task-rest_run-01_bold.nii.gz"))?;
    fs::File::create(root.join("sub-01").join("func").join("sub-01_task-rest_run-01_events.tsv"))?;
    fs::File::create(root.join("sub-02").join("func").join("sub-02_task-rest_run-01_bold.nii.gz"))?;

    // Create event file content
    let events_content = "onset\tduration\ttrial_type\nresponse_time\n0.0\t2.0\tgolden\t1.2\n5.0\t2.0\tscrambled\t1.5\n";
    fs::write(
        root.join("sub-01").join("func").join("sub-01_task-rest_run-01_events.tsv"),
        events_content
    )?;

    println!("✅ Created test BIDS dataset at: {}", root.display());

    // Test 1: Create BidsProject
    println!("\n🧪 Test 1: Creating BidsProject...");
    let project = BidsProject::new(root)?;
    println!("✅ Successfully created BidsProject: {}", project.name);

    // Test 2: Get participants
    println!("\n🧪 Test 2: Getting participants...");
    let participants = project.participants();
    println!("✅ Found {} participants: {:?}", participants.len(), participants);
    assert_eq!(participants.len(), 2);
    assert!(participants.contains(&"sub-01".to_string()));
    assert!(participants.contains(&"sub-02".to_string()));

    // Test 3: Get tasks
    println!("\n🧪 Test 3: Getting tasks...");
    let tasks = project.tasks();
    println!("✅ Found {} tasks: {:?}", tasks.len(), tasks);
    assert!(!tasks.is_empty());

    // Test 4: Search for functional scans
    println!("\n🧪 Test 4: Searching for functional scans...");
    let func_scans = project.func_scans().collect()?;
    println!("✅ Found {} functional scans", func_scans.len());
    for scan in &func_scans {
        println!("  - {}", scan.path.display());
    }
    assert!(!func_scans.is_empty());

    // Test 5: Search with filters
    println!("\n🧪 Test 5: Searching with subject filter...");
    let sub01_scans = project.func_scans()
        .subject("01")
        .collect()?;
    println!("✅ Found {} scans for sub-01", sub01_scans.len());
    assert!(!sub01_scans.is_empty());

    // Test 6: Search for event files
    println!("\n🧪 Test 6: Searching for event files...");
    let event_files = project.search()
        .suffix("events")
        .collect()?;
    println!("✅ Found {} event files", event_files.len());
    for event_file in &event_files {
        println!("  - {}", event_file.path.display());
    }

    // Test 7: Read event data
    if !event_files.is_empty() {
        println!("\n🧪 Test 7: Reading event data...");
        let events_data = project.read_events()
            .subject("01")
            .task("rest")
            .collect()?;
        println!("✅ Successfully read event data: {} files", events_data.len());

        if let Some(first_events) = events_data.first() {
            println!("  - First event file has {} trials", first_events.onset.len());
            if !first_events.onset.is_empty() {
                println!("  - First onset: {}", first_events.onset[0]);
                println!("  - First duration: {}", first_events.duration[0]);
            }
        }
    }

    // Test 8: Project summary
    println!("\n🧪 Test 8: Getting project summary...");
    let summary = project.summary();
    println!("✅ Project summary:");
    println!("  - Name: {}", summary.name);
    println!("  - Participants: {}", summary.n_participants);
    println!("  - Sessions: {}", summary.n_sessions);
    println!("  - Tasks: {}", summary.n_tasks);
    println!("  - Files: {}", summary.n_files);

    println!("\n🎉 All tests passed! Core BIDS functionality is working correctly.");
    println!("📦 Ready for v0.1.0 release with core functionality (dataframes temporarily disabled)");

    Ok(())
}

